def _dc_excepthook(et, ev, tb):
    import traceback as _tb
    print(f"[DC-FATAL] UNHANDLED EXCEPTION: {et.__name__}: {ev}", flush=True)
    for _line in _tb.format_exception(et, ev, tb):
        print(f"[DC-FATAL] {_line.rstrip()}", flush=True)
    sys.__excepthook__(et, ev, tb)
sys.excepthook = _dc_excepthook

