def fix_fk_constraints():
    """DC Protocol: Fix FK constraint conflicts that cause 500 errors on employee delete
    
    Handles two types of issues:
    1. NOT NULL + ON DELETE SET NULL conflicts (column can't be set to NULL)
    2. NO ACTION delete rules (blocks deletion entirely)
    """
    from sqlalchemy import text
    import signal
    
    # DC Protocol (Dec 24, 2025): Add timeout protection for production
    print("[DC-FK-FIX] Starting FK constraint check...", flush=True)
    
    try:
        with engine.connect() as conn:
            print("[DC-FK-FIX] Database connection established", flush=True)
            conn.execute(text("SET statement_timeout = 30000"))
            # Part 1: Fix NOT NULL + SET NULL conflicts
            conflict_check = conn.execute(text("""
                SELECT c.table_name, c.column_name
                FROM information_schema.columns c
                JOIN information_schema.key_column_usage kcu 
                    ON c.table_name = kcu.table_name AND c.column_name = kcu.column_name
                JOIN information_schema.table_constraints tc 
                    ON kcu.constraint_name = tc.constraint_name
                JOIN information_schema.constraint_column_usage ccu 
                    ON tc.constraint_name = ccu.constraint_name
                JOIN information_schema.referential_constraints rc 
                    ON tc.constraint_name = rc.constraint_name
                WHERE tc.constraint_type = 'FOREIGN KEY' 
                AND ccu.table_name = 'staff_employees'
                AND c.is_nullable = 'NO'
                AND rc.delete_rule = 'SET NULL'
            """))
            conflicts = conflict_check.fetchall()
            
            if conflicts:
                logging.info(f"[DC-FK-FIX] Found {len(conflicts)} NOT NULL conflicts, fixing...")
                for table_name, column_name in conflicts:
                    conn.execute(text(f"ALTER TABLE {table_name} ALTER COLUMN {column_name} DROP NOT NULL"))
                    logging.info(f"[DC-FK-FIX] Fixed NOT NULL on {table_name}.{column_name}")
                conn.commit()
                logging.info("[DC-FK-FIX] All NOT NULL conflicts fixed")
            else:
                logging.info("[DC-FK-FIX] No NOT NULL conflicts found")
            
            # Part 2: Fix NO ACTION constraints (blocks employee deletion)
            no_action_check = conn.execute(text("""
                SELECT tc.constraint_name, tc.table_name, kcu.column_name
                FROM information_schema.table_constraints tc
                JOIN information_schema.key_column_usage kcu ON tc.constraint_name = kcu.constraint_name
                JOIN information_schema.constraint_column_usage ccu ON tc.constraint_name = ccu.constraint_name
                JOIN information_schema.referential_constraints rc ON tc.constraint_name = rc.constraint_name
                WHERE ccu.table_name = 'staff_employees' AND rc.delete_rule = 'NO ACTION'
            """))
            no_action_constraints = no_action_check.fetchall()
            
            if no_action_constraints:
                logging.info(f"[DC-FK-FIX] Found {len(no_action_constraints)} NO ACTION constraints, converting to SET NULL...")
                for constraint_name, table_name, column_name in no_action_constraints:
                    try:
                        # Step 1: Drop the constraint
                        conn.execute(text(f"ALTER TABLE {table_name} DROP CONSTRAINT IF EXISTS {constraint_name}"))
                        logging.info(f"[DC-FK-FIX] Dropped constraint {constraint_name}")
                        
                        # Step 2: Ensure column is nullable
                        conn.execute(text(f"ALTER TABLE {table_name} ALTER COLUMN {column_name} DROP NOT NULL"))
                        logging.info(f"[DC-FK-FIX] Made {table_name}.{column_name} nullable")
                        
                        # Step 3: Recreate with ON DELETE SET NULL
                        conn.execute(text(f"""
                            ALTER TABLE {table_name} 
                            ADD CONSTRAINT {constraint_name} 
                            FOREIGN KEY ({column_name}) REFERENCES staff_employees(id) ON DELETE SET NULL
                        """))
                        logging.info(f"[DC-FK-FIX] Recreated {constraint_name} with ON DELETE SET NULL")
                    except Exception as inner_e:
                        logging.warning(f"[DC-FK-FIX] Could not fix {constraint_name}: {inner_e}")
                        continue
                conn.commit()
                logging.info("[DC-FK-FIX] All NO ACTION constraints converted to SET NULL")
            else:
                logging.info("[DC-FK-FIX] No NO ACTION constraints found")
            
            staff_actor_fks = [
                'bonanza_approved_by_fkey', 'bonanza_deleted_by_fkey',
                'fk_dynamic_bonanza_approved_by', 'fk_dynamic_bonanza_created_by',
                'banner_approved_by_fkey', 'banner_created_by_fkey',
                'coupon_management_approved_by_fkey', 'coupon_management_created_by_fkey',
                'enhanced_coupon_approved_by_fkey', 'enhanced_coupon_created_by_fkey',
                'coupon_request_approved_by_fkey', 'coupon_transfer_request_approved_by_fkey',
                'pin_approved_by_fkey', 'pin_created_by_fkey',
                'pin_request_approved_by_fkey', 'pin_transfer_request_approved_by_fkey',
                'custom_banner_created_by_fkey', 'custom_template_created_by_fkey',
                'customized_gifts_created_by_fkey', 'dynamic_field_created_by_fkey',
                'feedback_categories_created_by_fkey', 'feedback_submissions_approved_by_fkey',
                'birthday_messages_created_by_fkey', 'bulk_withdrawal_batch_created_by_fkey',
                'allowance_scheme_selector_created_by_fkey', 'red_coupon_approval_approved_by_fkey',
            ]
            dropped_count = 0
            for fk_name in staff_actor_fks:
                chk = conn.execute(text("""
                    SELECT table_name FROM information_schema.table_constraints
                    WHERE constraint_name = :fk AND constraint_type = 'FOREIGN KEY'
                """), {"fk": fk_name}).fetchone()
                if chk:
                    conn.execute(text(f'ALTER TABLE "{chk[0]}" DROP CONSTRAINT IF EXISTS "{fk_name}"'))
                    logging.info(f"[DC-FK-FIX] Dropped invalid FK {fk_name} on {chk[0]} (staff emp_codes not in user table)")
                    dropped_count += 1
            if dropped_count:
                conn.commit()
                logging.info(f"[DC-FK-FIX] Dropped {dropped_count} invalid FK constraints (staff actor columns referencing user table)")
                
    except Exception as e:
        logging.warning(f"[DC-FK-FIX] Could not check/fix FK constraints: {e}")

def fix_status_constraint():
    """DC Protocol: Fix status CHECK constraint to allow deactivated/resigned statuses"""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            # Check if constraint allows 'deactivated'
            check_result = conn.execute(text("""
                SELECT pg_get_constraintdef(oid) as def
                FROM pg_constraint 
                WHERE conname = 'staff_employees_status_check'
            """))
            row = check_result.fetchone()
            
            if row:
                constraint_def = row[0] if row else ''
                if 'deactivated' not in constraint_def:
                    logging.info("[DC-STATUS-FIX] Updating status constraint to include deactivated/resigned...")
                    conn.execute(text("ALTER TABLE staff_employees DROP CONSTRAINT IF EXISTS staff_employees_status_check"))
                    conn.execute(text("""
                        ALTER TABLE staff_employees ADD CONSTRAINT staff_employees_status_check 
                        CHECK (status IN ('active', 'inactive', 'suspended', 'terminated', 'deactivated', 'resigned'))
                    """))
                    conn.commit()
                    logging.info("[DC-STATUS-FIX] Status constraint updated successfully")
                else:
                    logging.info("[DC-STATUS-FIX] Status constraint already includes deactivated")
            else:
                logging.info("[DC-STATUS-FIX] No status constraint found, adding one...")
                conn.execute(text("""
                    ALTER TABLE staff_employees ADD CONSTRAINT staff_employees_status_check 
                    CHECK (status IN ('active', 'inactive', 'suspended', 'terminated', 'deactivated', 'resigned'))
                """))
                conn.commit()
                logging.info("[DC-STATUS-FIX] Status constraint added successfully")
    except Exception as e:
        logging.warning(f"[DC-STATUS-FIX] Could not fix status constraint: {e}")


