def fix_partner_category_constraint():
    """DC Protocol Jan 2026 (updated Mar 2026): Ensure partner_category_check includes all valid categories."""
    from sqlalchemy import text
    FULL_CATEGORIES = "('DEALER','DISTRIBUTOR','VENDOR','REAL_DREAM_PARTNER','SERVICE_CENTER','VGK_TEAM')"
    try:
        with engine.connect() as conn:
            check_result = conn.execute(text("""
                SELECT pg_get_constraintdef(oid) as def
                FROM pg_constraint 
                WHERE conname = 'partner_category_check'
            """))
            row = check_result.fetchone()

            if row:
                constraint_def = row[0] if row else ''
                missing = [c for c in ('SERVICE_CENTER', 'VGK_TEAM', 'REAL_DREAM_PARTNER') if c not in constraint_def]
                if missing:
                    logging.info(f"[DC-PARTNER-FIX] Updating partner_category_check — missing: {missing}")
                    conn.execute(text("ALTER TABLE official_partners DROP CONSTRAINT IF EXISTS partner_category_check"))
                    conn.execute(text(
                        f"ALTER TABLE official_partners ADD CONSTRAINT partner_category_check "
                        f"CHECK (category IN {FULL_CATEGORIES})"
                    ))
                    conn.commit()
                    logging.info("[DC-PARTNER-FIX] ✅ Partner category constraint updated with all categories")
                else:
                    logging.info("[DC-PARTNER-FIX] ✅ Constraint already includes all required categories")
            else:
                logging.info("[DC-PARTNER-FIX] No category constraint found — skipping")
    except Exception as e:
        logging.warning(f"[DC-PARTNER-FIX] Could not update constraint: {e}")


