def add_partner_kyc_columns():
    """DC Protocol Mar 2026: Add partner_id to kyc_document and kyc_status to official_partners."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            # 1. Make owner_id nullable (partner KYC records have no owner_id)
            try:
                conn.execute(text("ALTER TABLE kyc_document ALTER COLUMN owner_id DROP NOT NULL"))
                logging.info("[DC-PARTNER-KYC] kyc_document.owner_id made nullable")
            except Exception:
                pass

            # 2. Add partner_id FK to kyc_document
            exists = conn.execute(text(
                "SELECT 1 FROM information_schema.columns "
                "WHERE table_name='kyc_document' AND column_name='partner_id'"
            )).fetchone()
            if not exists:
                conn.execute(text(
                    "ALTER TABLE kyc_document ADD COLUMN partner_id INTEGER "
                    "REFERENCES official_partners(id) ON DELETE CASCADE"
                ))
                logging.info("[DC-PARTNER-KYC] Added kyc_document.partner_id")

            # 3. Add kyc_status to official_partners
            exists2 = conn.execute(text(
                "SELECT 1 FROM information_schema.columns "
                "WHERE table_name='official_partners' AND column_name='kyc_status'"
            )).fetchone()
            if not exists2:
                conn.execute(text(
                    "ALTER TABLE official_partners ADD COLUMN kyc_status VARCHAR(30) DEFAULT 'Not Submitted'"
                ))
                logging.info("[DC-PARTNER-KYC] Added official_partners.kyc_status")

            # 4. Widen valid_status constraint to include 'Staff Validated' and 'Not Uploaded'
            try:
                conn.execute(text("ALTER TABLE kyc_document DROP CONSTRAINT IF EXISTS valid_status"))
                conn.execute(text(
                    "ALTER TABLE kyc_document ADD CONSTRAINT valid_status "
                    "CHECK (status IN ('Pending', 'Staff Validated', 'Approved', 'Rejected', 'Not Uploaded'))"
                ))
                logging.info("[DC-PARTNER-KYC] kyc_document.valid_status constraint widened to include Staff Validated")
            except Exception as e2:
                logging.warning(f"[DC-PARTNER-KYC] valid_status constraint update failed: {e2}")

            # 5. Drop bad FK on reviewed_by_id — this field stores staff emp_codes, not user IDs
            try:
                conn.execute(text("ALTER TABLE kyc_document DROP CONSTRAINT IF EXISTS kyc_document_reviewed_by_id_fkey"))
                logging.info("[DC-PARTNER-KYC] Dropped kyc_document_reviewed_by_id_fkey (FK was wrong — field is an audit VARCHAR)")
            except Exception as e3:
                logging.warning(f"[DC-PARTNER-KYC] reviewed_by_id FK drop failed: {e3}")

            conn.commit()
            logging.info("[DC-PARTNER-KYC] Partner KYC column migration complete")
    except Exception as e:
        logging.warning(f"[DC-PARTNER-KYC] Migration failed: {e}")


