def create_vgk_tables():
    """DC Protocol Mar 2026: CREATE IF NOT EXISTS for VGK Team tables."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS vgk_team_commission_config (
                    id SERIAL PRIMARY KEY,
                    company_id INTEGER NOT NULL REFERENCES associated_companies(id),
                    category_id INTEGER NOT NULL REFERENCES signup_categories(id),
                    level1_pct NUMERIC(5,2) NOT NULL DEFAULT 5.0,
                    level2_pct NUMERIC(5,2) NOT NULL DEFAULT 3.0,
                    level3_pct NUMERIC(5,2) NOT NULL DEFAULT 1.0,
                    monthly_target NUMERIC(15,2) NOT NULL DEFAULT 0,
                    bonus_pct NUMERIC(5,2) NOT NULL DEFAULT 0,
                    markup_pct NUMERIC(5,2) NOT NULL DEFAULT 0,
                    is_active BOOLEAN NOT NULL DEFAULT TRUE,
                    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    UNIQUE (company_id, category_id)
                )
            """))
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS vgk_team_income_entries (
                    id SERIAL PRIMARY KEY,
                    company_id INTEGER NOT NULL REFERENCES associated_companies(id),
                    entry_number VARCHAR(30) NOT NULL,
                    partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                    source_lead_id INTEGER,
                    source_transaction_id INTEGER,
                    category_id INTEGER REFERENCES signup_categories(id) ON DELETE SET NULL,
                    level SMALLINT NOT NULL CHECK (level BETWEEN 0 AND 3),
                    revenue_amount NUMERIC(15,2) NOT NULL DEFAULT 0,
                    commission_pct NUMERIC(5,2) NOT NULL DEFAULT 0,
                    commission_amount NUMERIC(15,2) NOT NULL DEFAULT 0,
                    bonus_amount NUMERIC(15,2) NOT NULL DEFAULT 0,
                    status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                        CHECK (status IN ('PENDING','CONFIRMED','CANCELLED')),
                    notes TEXT,
                    confirmed_at TIMESTAMP,
                    confirmed_by INTEGER,
                    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    UNIQUE (company_id, entry_number)
                )
            """))
            conn.execute(text(
                "CREATE INDEX IF NOT EXISTS idx_vgk_income_partner_status "
                "ON vgk_team_income_entries (company_id, partner_id, status)"
            ))
            conn.execute(text(
                "CREATE INDEX IF NOT EXISTS idx_vgk_income_lead "
                "ON vgk_team_income_entries (company_id, source_lead_id)"
            ))
            conn.commit()
            logging.info("[DC-VGK] VGK Team tables created/verified")
    except Exception as e:
        logging.warning(f"[DC-VGK] Table creation failed: {e}")


def add_terms_platform_and_vgk_acceptance():
    """DC Protocol Mar 2026: Add platform_type to T&C versions; add T&C tracking to official_partners; create VGK acceptance log."""
    from sqlalchemy import text
    partner_cols = [
        ("accepted_terms_version", "VARCHAR(20)"),
        ("terms_accepted_at", "TIMESTAMP"),
    ]
    tc_cols = [
        ("platform_type", "VARCHAR(10) NOT NULL DEFAULT 'MNR'"),
    ]
    try:
        with engine.connect() as conn:
            for col, defn in partner_cols:
                exists = conn.execute(text(
                    "SELECT 1 FROM information_schema.columns WHERE table_name='official_partners' AND column_name=:c"
                ), {"c": col}).fetchone()
                if not exists:
                    conn.execute(text(f"ALTER TABLE official_partners ADD COLUMN {col} {defn}"))
                    logging.info(f"[DC-TERMS] Added official_partners.{col}")
            for col, defn in tc_cols:
                exists = conn.execute(text(
                    "SELECT 1 FROM information_schema.columns WHERE table_name='terms_and_conditions_versions' AND column_name=:c"
                ), {"c": col}).fetchone()
                if not exists:
                    conn.execute(text(f"ALTER TABLE terms_and_conditions_versions ADD COLUMN {col} {defn}"))
                    logging.info(f"[DC-TERMS] Added terms_and_conditions_versions.{col}")
            conn.commit()
    except Exception as e:
        logging.warning(f"[DC-TERMS] Column migration failed: {e}")
    try:
        with engine.connect() as conn:
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS vgk_terms_acceptance_log (
                    id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                    partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                    version VARCHAR(20) NOT NULL,
                    ip_address VARCHAR(45),
                    user_agent TEXT,
                    accepted_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    created_at TIMESTAMP NOT NULL DEFAULT NOW()
                )
            """))
            conn.execute(text(
                "CREATE INDEX IF NOT EXISTS idx_vgk_terms_log_partner ON vgk_terms_acceptance_log (partner_id)"
            ))
            conn.commit()
            logging.info("[DC-TERMS] vgk_terms_acceptance_log table ready")
    except Exception as e:
        logging.warning(f"[DC-TERMS] vgk_terms_acceptance_log creation failed (non-fatal): {e}")


def create_vgk_coupon_tables():
    """DC Protocol Mar 2026: CREATE IF NOT EXISTS for VGK Member Coupon System tables.
    Each table in its own connection to avoid sequence-conflict cascade failures."""
    from sqlalchemy import text

    _tables = [
        ("vgk_coupon_purchases", """
            CREATE TABLE IF NOT EXISTS vgk_coupon_purchases (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                quantity INTEGER NOT NULL DEFAULT 1,
                bonus_quantity INTEGER NOT NULL DEFAULT 0,
                unit_price NUMERIC(12,2) NOT NULL DEFAULT 5000,
                total_amount NUMERIC(12,2) NOT NULL,
                payment_method VARCHAR(50),
                transaction_ref VARCHAR(100),
                payment_proof_url VARCHAR(500),
                payment_notes TEXT,
                status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                    CHECK (status IN ('PENDING','APPROVED','REJECTED')),
                approved_by INTEGER REFERENCES staff_employees(id),
                approved_at TIMESTAMP,
                rejection_reason TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_coupon_ledger", """
            CREATE TABLE IF NOT EXISTS vgk_coupon_ledger (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                transaction_type VARCHAR(30) NOT NULL
                    CHECK (transaction_type IN ('purchase_credit','transfer_in','transfer_out','activation_used','admin_credit','admin_debit')),
                quantity INTEGER NOT NULL,
                related_partner_id INTEGER REFERENCES official_partners(id) ON DELETE SET NULL,
                purchase_id BIGINT,
                notes TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_member_activation_requests", """
            CREATE TABLE IF NOT EXISTS vgk_member_activation_requests (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                requesting_partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                target_partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                coupon_ledger_id BIGINT,
                status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                    CHECK (status IN ('PENDING','APPROVED','REJECTED')),
                approved_by INTEGER REFERENCES staff_employees(id),
                approved_at TIMESTAMP,
                rejection_reason TEXT,
                notes TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_pin_purchase_requests", """
            CREATE TABLE IF NOT EXISTS vgk_pin_purchase_requests (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                amount NUMERIC(12,2) NOT NULL DEFAULT 5000,
                payment_method VARCHAR(50),
                transaction_ref VARCHAR(100),
                payment_screenshot_url VARCHAR(500),
                payment_notes TEXT,
                status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
                    CHECK (status IN ('PENDING','APPROVED','REJECTED')),
                request_date TIMESTAMP NOT NULL DEFAULT NOW(),
                approved_by INTEGER REFERENCES staff_employees(id),
                approved_at TIMESTAMP,
                rejection_reason TEXT,
                staff_notes TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
    ]
    _indexes = [
        "CREATE INDEX IF NOT EXISTS idx_vgk_coupon_purchases_partner ON vgk_coupon_purchases (partner_id, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_coupon_ledger_partner ON vgk_coupon_ledger (partner_id)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_member_act_req_target ON vgk_member_activation_requests (target_partner_id, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_pin_req_partner_status ON vgk_pin_purchase_requests (partner_id, status)",
    ]
    for table_name, ddl in _tables:
        try:
            with engine.connect() as conn:
                conn.execute(text(ddl))
                conn.commit()
                logging.info(f"[DC-VGK] Table {table_name} created/verified")
        except Exception as e:
            logging.warning(f"[DC-VGK] Table {table_name} already exists or failed (non-fatal): {e}")
    for idx_sql in _indexes:
        try:
            with engine.connect() as conn:
                conn.execute(text(idx_sql))
                conn.commit()
        except Exception:
            pass


def fix_vgk_coupon_ledger_schema():
    """DC Protocol Mar 2026: Extend vgk_coupon_ledger to support bonus_credit and manual_adjustment
    transaction types, and add reference_id column for activation request linking."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            # Drop old narrow constraint and replace with full set
            conn.execute(text(
                "ALTER TABLE vgk_coupon_ledger "
                "DROP CONSTRAINT IF EXISTS vgk_coupon_ledger_transaction_type_check"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_coupon_ledger "
                "ADD CONSTRAINT vgk_coupon_ledger_transaction_type_check "
                "CHECK (transaction_type IN ("
                "  'purchase_credit','bonus_credit','transfer_in','transfer_out',"
                "  'activation_used','admin_credit','admin_debit','manual_adjustment'"
                "))"
            ))
            # Add reference_id column for linking to activation requests
            conn.execute(text(
                "ALTER TABLE vgk_coupon_ledger "
                "ADD COLUMN IF NOT EXISTS reference_id BIGINT"
            ))
            conn.commit()
        print("[DC-VGK-COUPON] ✅ vgk_coupon_ledger schema updated: bonus_credit, manual_adjustment, reference_id", flush=True)
    except Exception as e:
        print(f"[DC-VGK-COUPON] ⚠️  vgk_coupon_ledger schema fix failed (non-fatal): {e}", flush=True)


def add_vgk_support_confirmation_schema():
    """DC Protocol Apr 2026: Add support confirmation columns to vgk_team_income_entries.
    Tracks whether Source (L1) or Staff confirmed that Senior (L2) / Extended (L3) actually
    supported the deal. If unconfirmed at CONFIRM time, 30/30/30/10 redistribution fires.
    """
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            cols = [
                ("support_confirmed", "BOOLEAN DEFAULT NULL"),
                ("support_confirmed_at", "TIMESTAMP DEFAULT NULL"),
                ("support_confirmed_by_id", "INTEGER DEFAULT NULL"),
                ("support_confirmed_by_type", "VARCHAR(20) DEFAULT NULL"),
            ]
            for col_name, col_def in cols:
                try:
                    exists = conn.execute(text(
                        "SELECT 1 FROM information_schema.columns "
                        "WHERE table_name='vgk_team_income_entries' AND column_name=:c"
                    ), {"c": col_name}).fetchone()
                    if not exists:
                        conn.execute(text(
                            f"ALTER TABLE vgk_team_income_entries ADD COLUMN {col_name} {col_def}"
                        ))
                        logging.info(f"[DC-VGK-SUPPORT] Added vgk_team_income_entries.{col_name}")
                except Exception as ce:
                    logging.debug(f"[DC-VGK-SUPPORT] {col_name}: {ce}")
            conn.commit()
        print("[DC-VGK-SUPPORT] ✅ Support confirmation columns added to vgk_team_income_entries", flush=True)
    except Exception as e:
        print(f"[DC-VGK-SUPPORT] ⚠️  support confirmation schema failed (non-fatal): {e}", flush=True)


def seed_vgk_support_scenarios():
    """
    DC Protocol Apr 2026: Seed 6 demo leads + L2/L3 income entries covering all support_confirmed
    scenarios for development checking. Only runs on non-production environments.
    Idempotent — uses sentinel entry_number 'VGK-DEMO-S00' to detect prior run.
    """
    import os
    if os.environ.get('REPLIT_DEPLOYMENT') == '1':
        return  # skip production

    from sqlalchemy import text as _t
    from decimal import Decimal as _D
    from datetime import datetime as _dt

    try:
        with engine.connect() as c:
            # Idempotency check
            already = c.execute(_t(
                "SELECT id FROM vgk_team_income_entries WHERE entry_number='VGK-DEMO-S00' LIMIT 1"
            )).first()
            if already:
                print("[DC-VGK-DEMO] ✅ Support scenario seeds already present — skipping", flush=True)
                return

            # Resolve required IDs
            cid = c.execute(_t("SELECT id FROM associated_companies WHERE id=4 LIMIT 1")).scalar()
            if not cid:
                cid = c.execute(_t("SELECT MIN(id) FROM associated_companies")).scalar()
            if not cid:
                print("[DC-VGK-DEMO] ⚠️ No company found — skipping", flush=True)
                return

            # Partner IDs: L1=Rajesh(26), Guru L2=Priya(27), ZGuru L3=Sunita(29), Support L4=Ravi(30)
            l1_pid = c.execute(_t("SELECT id FROM official_partners WHERE partner_code='VGK07104937' LIMIT 1")).scalar() or 26
            l2_pid = c.execute(_t("SELECT id FROM official_partners WHERE partner_code='VGK07109955' LIMIT 1")).scalar() or 27
            l3_pid = c.execute(_t("SELECT id FROM official_partners WHERE partner_code='VGK07102949' LIMIT 1")).scalar() or 29
            l4_pid = c.execute(_t("SELECT id FROM official_partners WHERE partner_code='VGK07107572' LIMIT 1")).scalar() or 30

            # 6 demo scenarios
            SCENARIOS = [
                # (label, l2_confirmed, l3_confirmed, has_l3)
                ("Both Supported",           True,  True,  True),
                ("Guru OK, ZGuru Denied",    True,  False, True),
                ("Guru Denied, ZGuru OK",    False, True,  True),
                ("Both Denied (Redist)",     False, False, True),
                ("Both Pending (No decision)",None,  None,  True),
                ("Guru Only, Pending",        None,  None,  False),
            ]

            now = _dt.utcnow()
            created_leads = []
            for i, (label, l2_sc, l3_sc, has_l3) in enumerate(SCENARIOS, 1):
                # Create CRM lead
                lead_row = c.execute(_t(
                    "INSERT INTO crm_leads (name, phone, status, priority, looking_for, description, "
                    "handler_type, company_id, associated_partner_id, vgk_field_support_id, created_at, updated_at) "
                    "VALUES (:name, :phone, 'interested', 'high', 'Solar', :desc, 'unassigned', :cid, :l1, :l4, :now, :now) "
                    "RETURNING id"
                ), {
                    "name": f"[DEMO] {label}",
                    "phone": f"9700000{i:03d}",
                    "desc": f"VGK Support Scenario {i}: {label}. Used for dev/QA testing.",
                    "cid": cid, "l1": l1_pid, "l4": l4_pid, "now": now
                }).fetchone()
                lead_id = lead_row[0]
                created_leads.append(lead_id)

                # Sentinel entry for idempotency (level=0 entry)
                if i == 1:
                    c.execute(_t(
                        "INSERT INTO vgk_team_income_entries "
                        "(company_id, entry_number, partner_id, source_lead_id, level, "
                        " revenue_amount, commission_pct, commission_amount, bonus_amount, "
                        " required_points_debit, status, created_at, updated_at) "
                        "VALUES (:cid, 'VGK-DEMO-S00', :pid, :lid, 0, 100000, 0, 0, 0, 0, 'CONFIRMED', :now, :now)"
                    ), {"cid": cid, "pid": l1_pid, "lid": lead_id, "now": now})

                rev = _D('150000.00')
                l2_comm = _D('4500.00')   # 3% of 150k
                l3_comm = _D('1500.00')   # 1% of 150k

                # L1 entry (always confirmed, no support logic)
                c.execute(_t(
                    "INSERT INTO vgk_team_income_entries "
                    "(company_id, entry_number, partner_id, source_lead_id, level, "
                    " revenue_amount, commission_pct, commission_amount, bonus_amount, "
                    " required_points_debit, status, notes, created_at, updated_at) "
                    "VALUES (:cid, :en, :pid, :lid, 1, :rev, 5, 7500, 0, 0, 'PENDING', :notes, :now, :now)"
                ), {
                    "cid": cid, "en": f"VGK-DEMO-L1-{i:02d}", "pid": l1_pid, "lid": lead_id,
                    "rev": rev, "notes": f"Demo scenario {i} — L1 Source commission", "now": now
                })

                # L2 entry (Guru)
                c.execute(_t(
                    "INSERT INTO vgk_team_income_entries "
                    "(company_id, entry_number, partner_id, source_lead_id, level, "
                    " revenue_amount, commission_pct, commission_amount, bonus_amount, "
                    " required_points_debit, status, support_confirmed, notes, created_at, updated_at) "
                    "VALUES (:cid, :en, :pid, :lid, 2, :rev, 3, :comm, 0, 0, 'PENDING', :sc, :notes, :now, :now)"
                ), {
                    "cid": cid, "en": f"VGK-DEMO-L2-{i:02d}", "pid": l2_pid, "lid": lead_id,
                    "rev": rev, "comm": l2_comm, "sc": l2_sc,
                    "notes": f"Demo scenario {i} — Senior (L2) support_confirmed={l2_sc}", "now": now
                })

                if has_l3:
                    c.execute(_t(
                        "INSERT INTO vgk_team_income_entries "
                        "(company_id, entry_number, partner_id, source_lead_id, level, "
                        " revenue_amount, commission_pct, commission_amount, bonus_amount, "
                        " required_points_debit, status, support_confirmed, notes, created_at, updated_at) "
                        "VALUES (:cid, :en, :pid, :lid, 3, :rev, 1, :comm, 0, 0, 'PENDING', :sc, :notes, :now, :now)"
                    ), {
                        "cid": cid, "en": f"VGK-DEMO-L3-{i:02d}", "pid": l3_pid, "lid": lead_id,
                        "rev": rev, "comm": l3_comm, "sc": l3_sc,
                        "notes": f"Demo scenario {i} — Extended (L3) support_confirmed={l3_sc}", "now": now
                    })

            c.commit()
            print(
                f"[DC-VGK-DEMO] ✅ Seeded {len(SCENARIOS)} support scenario leads "
                f"(IDs: {created_leads}) with L2/L3 income entries",
                flush=True
            )

    except Exception as _e:
        print(f"[DC-VGK-DEMO] ⚠️  Scenario seed failed (non-fatal): {_e}", flush=True)


def fix_vgk_income_hold_schema():
    """DC Protocol Mar 2026: Add HOLD status and required_points_debit column to vgk_team_income_entries.
    Drops both old constraint names (SQLAlchemy-auto and manually-added) and installs a single
    clean constraint that includes HOLD."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            conn.execute(text(
                "ALTER TABLE vgk_team_income_entries "
                "ADD COLUMN IF NOT EXISTS required_points_debit NUMERIC(15,2) NOT NULL DEFAULT 0"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_team_income_entries "
                "DROP CONSTRAINT IF EXISTS vgk_income_status_check"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_team_income_entries "
                "DROP CONSTRAINT IF EXISTS vgk_team_income_entries_status_check"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_team_income_entries "
                "ADD CONSTRAINT vgk_income_status_check "
                "CHECK (status IN ('PENDING','CONFIRMED','CANCELLED','HOLD'))"
            ))
            conn.commit()
        print("[DC-VGK-HOLD] ✅ vgk_team_income_entries: HOLD status + required_points_debit added", flush=True)
    except Exception as e:
        print(f"[DC-VGK-HOLD] ⚠️  vgk_income_hold schema fix failed (non-fatal): {e}", flush=True)


def seed_vgk4u_member_menu_entries():
    """DC Protocol May 2026 (Task #33): Register the 16 VGK4U Member read-only modules
    as staff_menu_registry entries with audience_scope='vgk_member' and Zero-Default
    Access (is_default_visible=false, is_default_accessible=false). The sidebar sync
    routine deliberately preserves vgk_member-scope rows (DC_VGK4U_MEMBER_001) so they
    stay registered across re-syncs. Staff acquire visibility ONLY via the explicit
    Menu Access Control grant flow.
    """
    from sqlalchemy import text
    modules = [
        ('vgk4u_member_birthdays', 'VGK4U Birthdays', '/vgk/birthdays', 'bi-balloon-heart'),
        ('vgk4u_member_top_earners', 'VGK4U Top Earners', '/vgk/top-earners', 'bi-trophy-fill'),
        ('vgk4u_member_awards', 'VGK4U Awards', '/vgk/awards', 'bi-award-fill'),
        ('vgk4u_member_daywise_income', 'VGK4U Daywise Income', '/vgk/daywise-income', 'bi-calendar3'),
        ('vgk4u_member_income_types', 'VGK4U Income Types', '/vgk/income-types', 'bi-pie-chart-fill'),
        ('vgk4u_member_direct_summary', 'VGK4U Direct (L1)', '/vgk/direct-summary', 'bi-1-square-fill'),
        ('vgk4u_member_matching_summary', 'VGK4U Matching (L2)', '/vgk/matching-summary', 'bi-2-square-fill'),
        ('vgk4u_member_guru_summary', 'VGK4U Senior (L3)', '/vgk/guru-summary', 'bi-3-square-fill'),
        ('vgk4u_member_ved_summary', 'VGK4U VED (L4)', '/vgk/ved-summary', 'bi-4-square-fill'),
        ('vgk4u_member_ev_benefits', 'VGK4U EV Benefits', '/vgk/ev-benefits', 'bi-ev-station-fill'),
        ('vgk4u_member_ev_discount', 'VGK4U EV Discount', '/vgk/ev-discount', 'bi-tag-fill'),
        ('vgk4u_member_franchise_earnings', 'VGK4U Franchise Earnings', '/vgk/franchise-earnings', 'bi-shop-window'),
        ('vgk4u_member_insurance', 'VGK4U Insurance', '/vgk/insurance', 'bi-shield-fill-check'),
        ('vgk4u_member_training', 'VGK4U Training', '/vgk/training', 'bi-mortarboard-fill'),
        ('vgk4u_member_coupon_benefits', 'VGK4U Coupon Benefits', '/vgk/coupon-benefits', 'bi-ticket-perforated-fill'),
        ('vgk4u_member_my_submissions', 'VGK4U My Submissions', '/vgk/my-submissions', 'bi-file-text-fill'),
    ]
    new_in_registry = 0
    new_in_master = 0
    try:
        with engine.connect() as conn:
            for order, (code, name, route, icon) in enumerate(modules, start=1):
                existing = conn.execute(text(
                    "SELECT 1 FROM staff_menu_registry WHERE menu_code = :code"
                ), {"code": code}).fetchone()
                if not existing:
                    conn.execute(text("""
                        INSERT INTO staff_menu_registry
                          (menu_code, menu_name, route_path, menu_category, menu_icon,
                           display_order, audience_scope, source, is_default_visible,
                           is_default_accessible, is_active, is_system_default,
                           sidebar_section, sidebar_section_title, sidebar_section_order,
                           is_submenu, parent_section, menu_type)
                        VALUES (:code, :name, :route, 'vgk4u_member', :icon,
                                :ord, 'vgk_member', 'vgk4u_parity_phase1', false,
                                false, true, false,
                                'vgk4u_member', 'VGK4U MEMBER', 24,
                                false, NULL, 'page')
                    """), {"code": code, "name": name, "route": route, "icon": icon, "ord": order})
                    new_in_registry += 1
                # Master per active company (zero-default visibility)
                companies = conn.execute(text(
                    "SELECT id FROM associated_companies WHERE is_active = true"
                )).fetchall()
                for (company_id,) in companies:
                    exists_m = conn.execute(text(
                        "SELECT 1 FROM staff_menu_master WHERE company_id = :cid AND menu_code = :code"
                    ), {"cid": company_id, "code": code}).fetchone()
                    if not exists_m:
                        conn.execute(text("""
                            INSERT INTO staff_menu_master
                              (company_id, menu_code, menu_name, route_path, menu_category,
                               menu_icon, display_order, audience_scope, is_active,
                               is_default_visible, is_default_accessible,
                               sidebar_section, sidebar_section_title, sidebar_section_order)
                            VALUES (:cid, :code, :name, :route, 'vgk4u_member',
                                    :icon, :ord, 'vgk_member', true,
                                    false, false,
                                    'vgk4u_member', 'VGK4U MEMBER', 24)
                        """), {"cid": company_id, "code": code, "name": name, "route": route,
                                "icon": icon, "ord": order})
                        new_in_master += 1
            conn.commit()
        print(f"[DC-VGK4U-PARITY-MENU] ✅ Seeded {new_in_registry} new registry + {new_in_master} new master rows (vgk_member, zero-default-access)", flush=True)
    except Exception as e:
        print(f"[DC-VGK4U-PARITY-MENU] ⚠️ VGK4U member menu seed failed (non-fatal): {e}", flush=True)


def add_system_controls_vgk4u_flags():
    """DC Protocol May 2026 (Task #33): Add VGK4U Member Parity Phase 1 toggle columns
    to `app_settings` (NOT `system_control`). The ORM column definitions live on
    AppSettings (backend/app/models/system_control.py:274-289), so the runtime
    GET/PUT super-admin endpoints read & write from app_settings — this migration
    must target the same table or the toggles silently no-op.

    DC_T33_TOGGLE_001: single source of truth = `app_settings`.
    """
    from sqlalchemy import text
    cols = [
        'birthdays_vgk4u_enabled', 'top_earners_vgk4u_enabled', 'awards_vgk4u_enabled',
        'daywise_income_vgk4u_enabled', 'income_types_vgk4u_enabled',
        'direct_summary_vgk4u_enabled', 'matching_summary_vgk4u_enabled',
        'guru_summary_vgk4u_enabled', 'ved_summary_vgk4u_enabled',
        'ev_benefits_vgk4u_enabled', 'ev_discount_vgk4u_enabled',
        'franchise_earnings_vgk4u_enabled', 'insurance_vgk4u_enabled',
        'training_vgk4u_enabled', 'coupon_benefits_vgk4u_enabled',
        'my_submissions_vgk4u_enabled',
    ]
    try:
        with engine.connect() as conn:
            for col in cols:
                conn.execute(text(
                    f"ALTER TABLE app_settings ADD COLUMN IF NOT EXISTS {col} BOOLEAN NOT NULL DEFAULT TRUE"
                ))
            # Defensive cleanup: if a prior buggy run added these columns to
            # `system_control` they are dead weight — drop them so there is
            # exactly ONE source of truth.
            for col in cols:
                conn.execute(text(
                    f"ALTER TABLE system_control DROP COLUMN IF EXISTS {col}"
                ))
            # Ensure at least one row exists so reads/writes have a target
            conn.execute(text(
                "INSERT INTO app_settings (id) "
                "SELECT 1 WHERE NOT EXISTS (SELECT 1 FROM app_settings)"
            ))
            conn.commit()
        print(f"[DC-VGK4U-PARITY] ✅ {len(cols)} VGK4U toggle columns added to app_settings (single source of truth)", flush=True)
    except Exception as e:
        print(f"[DC-VGK4U-PARITY] ⚠️  app_settings VGK4U flags migration failed (non-fatal): {e}", flush=True)


