def create_vgk4u_phase2_tables():
    """DC Protocol May 2026 (Task #34): VGK4U Member Parity Phase 2.

    Creates 9 new additive tables for VGK4U member write-flow modules.
    All FK by `partner_id` to `official_partners`; `company_id` for
    multi-tenant segregation. Mirrors MNR-side schemas. CREATE IF NOT
    EXISTS — safe to re-run on every boot.

    Tables:
      - vgk_kyc_documents          — VGK4U member KYC submissions
      - vgk_kyc_blocking_log       — KYC rejection / block trail
      - vgk_bank_details           — VGK4U member bank details
      - vgk_bank_details_approval  — Bank approval workflow (Super → Finance)
      - vgk_feedback               — Feedback submissions by VGK4U members
      - vgk_feedback_media         — Media files attached to feedback
      - vgk_feedback_approval      — Per-media admin approval audit
      - vgk_announcements          — Approved feedback rolled into announcements
      - vgk_member_settings        — Per-member preferences (notif/theme/lang)
    """
    from sqlalchemy import text

    _tables = [
        ("vgk_kyc_documents", """
            CREATE TABLE IF NOT EXISTS vgk_kyc_documents (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                document_type VARCHAR(50) NOT NULL,
                file_path VARCHAR(500) NOT NULL,
                file_name VARCHAR(255),
                original_filename VARCHAR(255),
                file_size INTEGER,
                mime_type VARCHAR(50),
                compressed_path VARCHAR(500),
                compressed_size_bytes INTEGER,
                processing_status VARCHAR(20) DEFAULT 'pending',
                processed_at TIMESTAMP,
                compressed_checksum VARCHAR(64),
                has_compressed BOOLEAN DEFAULT FALSE,
                original_checksum VARCHAR(64),
                original_storage_type VARCHAR(20) DEFAULT 'object_storage',
                original_storage_key VARCHAR(500),
                download_filename VARCHAR(255),
                status VARCHAR(30) NOT NULL DEFAULT 'Pending',
                version INTEGER DEFAULT 1,
                previous_version_id BIGINT,
                is_current_version BOOLEAN DEFAULT TRUE,
                reviewed_by_staff_id INTEGER REFERENCES staff_employees(id),
                reviewed_at TIMESTAMP,
                admin_notes TEXT,
                rejection_reason TEXT,
                pan_number_encrypted TEXT,
                aadhaar_number_encrypted TEXT,
                pan_validated BOOLEAN,
                aadhaar_validated BOOLEAN,
                validation_errors TEXT,
                uploaded_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_kyc_blocking_log", """
            CREATE TABLE IF NOT EXISTS vgk_kyc_blocking_log (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                document_id BIGINT REFERENCES vgk_kyc_documents(id) ON DELETE SET NULL,
                block_reason TEXT NOT NULL,
                blocked_by_staff_id INTEGER REFERENCES staff_employees(id),
                unblocked_by_staff_id INTEGER REFERENCES staff_employees(id),
                unblocked_at TIMESTAMP,
                created_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_bank_details", """
            CREATE TABLE IF NOT EXISTS vgk_bank_details (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                bank_account_number VARCHAR(50) NOT NULL,
                bank_ifsc_code VARCHAR(20) NOT NULL,
                bank_account_holder VARCHAR(100) NOT NULL,
                bank_name VARCHAR(100),
                bank_branch_name VARCHAR(100),
                upi_id VARCHAR(100),
                cancelled_cheque_path VARCHAR(500),
                status VARCHAR(30) NOT NULL DEFAULT 'Pending',
                is_current BOOLEAN NOT NULL DEFAULT TRUE,
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_bank_details_approval", """
            CREATE TABLE IF NOT EXISTS vgk_bank_details_approval (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                bank_details_id BIGINT NOT NULL REFERENCES vgk_bank_details(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                bank_account_number VARCHAR(50) NOT NULL,
                bank_ifsc_code VARCHAR(20) NOT NULL,
                bank_account_holder VARCHAR(100) NOT NULL,
                bank_name VARCHAR(100),
                bank_branch_name VARCHAR(100),
                upi_id VARCHAR(100),
                super_admin_status VARCHAR(20) NOT NULL DEFAULT 'Pending',
                super_admin_id INTEGER REFERENCES staff_employees(id),
                super_admin_at TIMESTAMP,
                super_admin_notes TEXT,
                finance_admin_status VARCHAR(20) NOT NULL DEFAULT 'Pending',
                finance_admin_id INTEGER REFERENCES staff_employees(id),
                finance_admin_at TIMESTAMP,
                finance_admin_notes TEXT,
                final_status VARCHAR(20) NOT NULL DEFAULT 'Pending',
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_feedback", """
            CREATE TABLE IF NOT EXISTS vgk_feedback (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                category_id INTEGER REFERENCES feedback_categories(id) ON DELETE SET NULL,
                submission_type VARCHAR(20) NOT NULL DEFAULT 'text',
                title VARCHAR(200) NOT NULL,
                description TEXT,
                status VARCHAR(30) NOT NULL DEFAULT 'pending',
                approved_media_count INTEGER NOT NULL DEFAULT 0,
                rejected_media_count INTEGER NOT NULL DEFAULT 0,
                last_reviewed_at TIMESTAMP,
                last_reviewed_by_staff_id INTEGER REFERENCES staff_employees(id),
                is_visible BOOLEAN NOT NULL DEFAULT TRUE,
                hidden_by_staff_id INTEGER REFERENCES staff_employees(id),
                hidden_at TIMESTAMP,
                shares_count INTEGER NOT NULL DEFAULT 0,
                views_count INTEGER NOT NULL DEFAULT 0,
                display_order INTEGER,
                submitted_at TIMESTAMP NOT NULL DEFAULT NOW(),
                approved_at TIMESTAMP,
                approved_by_staff_id INTEGER REFERENCES staff_employees(id),
                visible_to VARCHAR(10) NOT NULL DEFAULT 'vgk',
                is_deleted BOOLEAN NOT NULL DEFAULT FALSE,
                deleted_at TIMESTAMP,
                deleted_by_staff_id INTEGER REFERENCES staff_employees(id)
            )
        """),
        ("vgk_feedback_media", """
            CREATE TABLE IF NOT EXISTS vgk_feedback_media (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                submission_id BIGINT NOT NULL REFERENCES vgk_feedback(id) ON DELETE CASCADE,
                file_path VARCHAR(500) NOT NULL,
                file_type VARCHAR(20) NOT NULL,
                file_size INTEGER,
                duration INTEGER,
                media_type VARCHAR(20) NOT NULL DEFAULT 'photo',
                media_status VARCHAR(20) NOT NULL DEFAULT 'pending',
                is_visible BOOLEAN NOT NULL DEFAULT TRUE,
                decided_at TIMESTAMP,
                decided_by_staff_id INTEGER REFERENCES staff_employees(id),
                decision_comment TEXT,
                thumbnail_url VARCHAR(500),
                checksum_sha256 VARCHAR(64),
                storage_type VARCHAR(20) DEFAULT 'object_storage',
                storage_key VARCHAR(500),
                created_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_feedback_approval", """
            CREATE TABLE IF NOT EXISTS vgk_feedback_approval (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                submission_id BIGINT NOT NULL REFERENCES vgk_feedback(id) ON DELETE CASCADE,
                media_id BIGINT REFERENCES vgk_feedback_media(id) ON DELETE CASCADE,
                action VARCHAR(20) NOT NULL,
                staff_id INTEGER REFERENCES staff_employees(id),
                comment TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_announcements", """
            CREATE TABLE IF NOT EXISTS vgk_announcements (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                source_feedback_id BIGINT REFERENCES vgk_feedback(id) ON DELETE SET NULL,
                partner_id INTEGER REFERENCES official_partners(id) ON DELETE SET NULL,
                company_id INTEGER REFERENCES associated_companies(id),
                title VARCHAR(200) NOT NULL,
                description TEXT,
                announcement_type VARCHAR(20) NOT NULL DEFAULT 'text',
                status VARCHAR(30) NOT NULL DEFAULT 'pending',
                cover_image_url VARCHAR(500),
                video_url VARCHAR(500),
                visible_to VARCHAR(10) NOT NULL DEFAULT 'vgk',
                is_visible BOOLEAN NOT NULL DEFAULT TRUE,
                shares_count INTEGER NOT NULL DEFAULT 0,
                views_count INTEGER NOT NULL DEFAULT 0,
                display_order INTEGER,
                published_at TIMESTAMP,
                approved_by_staff_id INTEGER REFERENCES staff_employees(id),
                rejected_at TIMESTAMP,
                rejected_by_staff_id INTEGER REFERENCES staff_employees(id),
                rejection_reason TEXT,
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
        ("vgk_member_settings", """
            CREATE TABLE IF NOT EXISTS vgk_member_settings (
                id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
                partner_id INTEGER NOT NULL UNIQUE REFERENCES official_partners(id) ON DELETE CASCADE,
                company_id INTEGER REFERENCES associated_companies(id),
                preferences JSONB NOT NULL DEFAULT '{}'::jsonb,
                notification_whatsapp BOOLEAN NOT NULL DEFAULT TRUE,
                notification_email BOOLEAN NOT NULL DEFAULT TRUE,
                notification_sms BOOLEAN NOT NULL DEFAULT FALSE,
                notification_push BOOLEAN NOT NULL DEFAULT TRUE,
                theme VARCHAR(20) NOT NULL DEFAULT 'light',
                language VARCHAR(10) NOT NULL DEFAULT 'en',
                created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                updated_at TIMESTAMP NOT NULL DEFAULT NOW()
            )
        """),
    ]

    _indexes = [
        "CREATE INDEX IF NOT EXISTS idx_vgk_kyc_doc_partner_status ON vgk_kyc_documents (partner_id, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_kyc_doc_company ON vgk_kyc_documents (company_id, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_kyc_block_partner ON vgk_kyc_blocking_log (partner_id)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_bank_partner ON vgk_bank_details (partner_id, is_current)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_bank_appr_status ON vgk_bank_details_approval (final_status, partner_id)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_feedback_partner_status ON vgk_feedback (partner_id, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_feedback_visible ON vgk_feedback (visible_to, is_visible, status)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_feedback_media_sub ON vgk_feedback_media (submission_id)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_feedback_approval_sub ON vgk_feedback_approval (submission_id, media_id)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_ann_status ON vgk_announcements (status, visible_to, is_visible)",
        "CREATE INDEX IF NOT EXISTS idx_vgk_ann_partner ON vgk_announcements (partner_id)",
    ]

    for table_name, ddl in _tables:
        try:
            with engine.connect() as conn:
                conn.execute(text(ddl))
                conn.commit()
                logging.info(f"[DC-VGK4U-P2] Table {table_name} created/verified")
        except Exception as e:
            logging.warning(f"[DC-VGK4U-P2] Table {table_name} failed (non-fatal): {e}")

    for idx_sql in _indexes:
        try:
            with engine.connect() as conn:
                conn.execute(text(idx_sql))
                conn.commit()
        except Exception:
            pass

    print("[DC-VGK4U-PARITY-P2] ✅ Phase-2 tables (kyc/bank/feedback/announcements/settings) created/verified", flush=True)


def seed_vgk4u_member_phase2_menu_entries():
    """DC Protocol May 2026 (Task #34): Register the 9 VGK4U Member write-flow
    pages as staff_menu_registry entries with audience_scope='vgk_member' and
    Zero-Default Access (is_default_visible=false, is_default_accessible=false).
    """
    from sqlalchemy import text
    modules = [
        ('vgk4u_member_feedback_submit',     'VGK4U Submit Feedback',  '/vgk/feedback',           'bi-chat-square-text'),
        ('vgk4u_member_announcements',       'VGK4U Announcements',    '/vgk/announcements',      'bi-megaphone-fill'),
        ('vgk4u_member_my_announcements',    'VGK4U My Announcements', '/vgk/my-announcements',   'bi-card-list'),
        ('vgk4u_member_kyc',                 'VGK4U KYC',              '/vgk/kyc',                'bi-person-badge-fill'),
        ('vgk4u_member_bank_details',        'VGK4U Bank Details',     '/vgk/bank-details',       'bi-bank2'),
        ('vgk4u_member_profile_edit',        'VGK4U Profile Edit',     '/vgk/profile-edit',       'bi-pencil-square'),
        ('vgk4u_member_settings',            'VGK4U Settings',         '/vgk/settings',           'bi-gear-fill'),
        ('vgk4u_member_coupon_activate',     'VGK4U Coupon Activate',  '/vgk/coupon-activate',    'bi-ticket-perforated'),
        ('vgk4u_member_coupon_progress',     'VGK4U Coupon Progress',  '/vgk/coupon-progress',    'bi-bar-chart-line'),
        ('vgk4u_member_coupon_transfer',     'VGK4U Coupon Transfer',  '/vgk/coupon-transfer',    'bi-arrow-left-right'),
    ]
    new_in_registry = 0
    new_in_master = 0
    try:
        with engine.connect() as conn:
            for order, (code, name, route, icon) in enumerate(modules, start=200):
                existing = conn.execute(text(
                    "SELECT 1 FROM staff_menu_registry WHERE menu_code = :code"
                ), {"code": code}).fetchone()
                if not existing:
                    conn.execute(text("""
                        INSERT INTO staff_menu_registry
                          (menu_code, menu_name, route_path, menu_category, menu_icon,
                           display_order, audience_scope, source, is_default_visible,
                           is_default_accessible, is_active, is_system_default,
                           sidebar_section, sidebar_section_title, sidebar_section_order,
                           is_submenu, parent_section, menu_type)
                        VALUES (:code, :name, :route, 'vgk4u_member', :icon,
                                :ord, 'vgk_member', 'vgk4u_parity_phase2', false,
                                false, true, false,
                                'vgk4u_member', 'VGK4U MEMBER', 24,
                                false, NULL, 'page')
                    """), {"code": code, "name": name, "route": route, "icon": icon, "ord": order})
                    new_in_registry += 1
                companies = conn.execute(text(
                    "SELECT id FROM associated_companies WHERE is_active = true"
                )).fetchall()
                for (company_id,) in companies:
                    exists_m = conn.execute(text(
                        "SELECT 1 FROM staff_menu_master WHERE company_id = :cid AND menu_code = :code"
                    ), {"cid": company_id, "code": code}).fetchone()
                    if not exists_m:
                        conn.execute(text("""
                            INSERT INTO staff_menu_master
                              (company_id, menu_code, menu_name, route_path, menu_category,
                               menu_icon, display_order, audience_scope, is_active,
                               is_default_visible, is_default_accessible,
                               sidebar_section, sidebar_section_title, sidebar_section_order)
                            VALUES (:cid, :code, :name, :route, 'vgk4u_member',
                                    :icon, :ord, 'vgk_member', true,
                                    false, false,
                                    'vgk4u_member', 'VGK4U MEMBER', 24)
                        """), {"cid": company_id, "code": code, "name": name, "route": route,
                                "icon": icon, "ord": order})
                        new_in_master += 1
            conn.commit()
        print(f"[DC-VGK4U-P2-MENU] ✅ Seeded {new_in_registry} registry + {new_in_master} master rows (zero-default)", flush=True)
    except Exception as e:
        print(f"[DC-VGK4U-P2-MENU] ⚠️ Phase-2 menu seed failed (non-fatal): {e}", flush=True)


def add_vgk_loyal_coupon_column():
    """DC Protocol Mar 2026: Add is_loyal_coupon flag to official_partners and
    expand vgk_points_ledger reason_code constraint to include LOYAL_BONUS."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            conn.execute(text(
                "ALTER TABLE official_partners "
                "ADD COLUMN IF NOT EXISTS is_loyal_coupon BOOLEAN NOT NULL DEFAULT FALSE"
            ))
            # DC Protocol Mar 2026: is_paid_activation added here (early) so bulk_menu_repair
            # (which queries official_partners) doesn't fail on startup ordering.
            conn.execute(text(
                "ALTER TABLE official_partners "
                "ADD COLUMN IF NOT EXISTS is_paid_activation BOOLEAN NOT NULL DEFAULT FALSE"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_points_ledger "
                "DROP CONSTRAINT IF EXISTS vgk_points_reason_check"
            ))
            conn.execute(text(
                "ALTER TABLE vgk_points_ledger "
                "ADD CONSTRAINT vgk_points_reason_check "
                "CHECK (reason_code IN ("
                "'WELCOME_BONUS','ACTIVATION_BONUS','LOYAL_BONUS','BONANZA_REWARD',"
                "'PRODUCT_DISCOUNT','COMMISSION_ADJUSTMENT','MANUAL_ADJUSTMENT','MIGRATION_BALANCE',"
                "'CAMPAIGN_BONUS','AUTO_REFILL'"
                "))"
            ))
            conn.commit()
        print("[DC-VGK-LOYAL] ✅ is_loyal_coupon column + LOYAL_BONUS reason code added", flush=True)
    except Exception as e:
        print(f"[DC-VGK-LOYAL] ⚠️  Loyal coupon schema migration failed (non-fatal): {e}", flush=True)


