def fix_welcome_coupon_constraints():
    """DC Protocol Feb 2026: Fix pin_purchase_request CHECK constraints to allow Welcome Coupon (₹0)
    
    Welcome Coupons have package_type='0', package_value=0, total_amount=0, payment_amount=0.
    Old constraints required strictly positive values (> 0) and didn't include '0' in valid_package_type.
    This fixes both constraints to allow zero values for Welcome Coupons.
    """
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            check_result = conn.execute(text("""
                SELECT c.conname, pg_get_constraintdef(c.oid)
                FROM pg_constraint c 
                JOIN pg_class t ON c.conrelid = t.oid
                JOIN pg_namespace n ON t.relnamespace = n.oid
                WHERE t.relname = 'pin_purchase_request'
                AND n.nspname = 'public'
                AND c.contype = 'c'
                AND c.conname IN ('positive_amounts', 'valid_package_type')
            """))
            constraints = {row[0]: row[1] for row in check_result.fetchall()}
            
            needs_fix = False
            pa_def = constraints.get('positive_amounts', '')
            vp_def = constraints.get('valid_package_type', '')
            
            print(f"[DC-WELCOME-FIX] Current positive_amounts: {pa_def or '(missing)'}", flush=True)
            print(f"[DC-WELCOME-FIX] Current valid_package_type: {vp_def or '(missing)'}", flush=True)
            
            pa_correct = pa_def and '>=' in pa_def
            if not pa_correct:
                needs_fix = True
                print("[DC-WELCOME-FIX] positive_amounts needs update — replacing strict > 0 with >= 0", flush=True)
                conn.execute(text("ALTER TABLE pin_purchase_request DROP CONSTRAINT IF EXISTS positive_amounts"))
                conn.execute(text("""
                    ALTER TABLE pin_purchase_request ADD CONSTRAINT positive_amounts 
                    CHECK (package_value >= 0 AND total_amount >= 0 AND payment_amount >= 0)
                """))
                print("[DC-WELCOME-FIX] positive_amounts updated to allow zero values", flush=True)
            
            vp_correct = vp_def and "'0'" in vp_def
            if not vp_correct:
                needs_fix = True
                print("[DC-WELCOME-FIX] valid_package_type needs update — adding '0' for Welcome Coupon", flush=True)
                conn.execute(text("ALTER TABLE pin_purchase_request DROP CONSTRAINT IF EXISTS valid_package_type"))
                conn.execute(text("""
                    ALTER TABLE pin_purchase_request ADD CONSTRAINT valid_package_type 
                    CHECK (package_type IN ('15000', '7500', '1000', '500', '0'))
                """))
                print("[DC-WELCOME-FIX] valid_package_type updated to include '0'", flush=True)
            
            if needs_fix:
                conn.commit()
                print("[DC-WELCOME-FIX] Welcome Coupon constraints fixed successfully", flush=True)
            else:
                print("[DC-WELCOME-FIX] Constraints already correct — no changes needed", flush=True)
    except Exception as e:
        print(f"[DC-WELCOME-FIX] Could not fix Welcome Coupon constraints: {e}", flush=True)


