_ETC_ADVISORY_LOCK_ID = 20260214

def create_etc_tables():
    """
    VGK4U ETC Training Centre — Student Master (DC Protocol - Feb 2026).
    Idempotent CREATE TABLE IF NOT EXISTS + seed 131 historical students.
    Registration ID format: VGK/1808XXXX/YYYY (year = batch start year)
    Student ID for marketplace discount: VGK1808XXXX (no slashes, 10% off)
    Cross-process guard: uses PostgreSQL advisory lock so only one worker
    (across all processes) can execute ETC seeding at a time.
    """
    from sqlalchemy import text as sa_text
    from app.core.database import engine as _db_engine
    with _db_engine.connect() as conn:
        acquired = conn.execute(
            sa_text("SELECT pg_try_advisory_lock(:lock_id)"),
            {"lock_id": _ETC_ADVISORY_LOCK_ID}
        ).scalar()
        if not acquired:
            logging.info("[ETC] Another worker holds the advisory lock — skipping ETC seeding")
            return
        try:
            _create_etc_tables_inner()
        finally:
            conn.execute(
                sa_text("SELECT pg_advisory_unlock(:lock_id)"),
                {"lock_id": _ETC_ADVISORY_LOCK_ID}
            )
            conn.commit()


