def fix_marketplace_margin_floor():
    """Raise margin_floor_percent from legacy 5.0 to 20.0 on all existing category configs.

    The 5% floor blocked partner (12%) and student (10%) discounts for ALL products.
    20% allows all configured discount modes (max 12%) to pass the margin guard.
    Idempotent: only updates rows where margin_floor_percent < 15.
    """
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            result = conn.execute(text(
                "UPDATE marketplace_category_config SET margin_floor_percent = 20.0 "
                "WHERE margin_floor_percent < 15"
            ))
            conn.commit()
            print(f"[DC-MARKET-FLOOR] ✅ margin_floor_percent raised to 20% on {result.rowcount} category config rows", flush=True)
    except Exception as e:
        logging.warning(f"[DC-MARKET-FLOOR] Migration error (non-fatal): {e}")


def fix_call_log_timezone():
    """CT Protocol Feb 2026: Fix call_datetime stored as UTC-naive → IST-naive.

    Root cause: mobile sends call_datetime as new Date().toISOString() (UTC, Z-suffix).
    Backend was stripping tz info and storing raw UTC as naive. Fixed in sync endpoint going forward.
    This one-time migration adds +5h30m to all existing records to convert UTC→IST.
    Guard: uses _ct_migrations table to ensure idempotent single-run execution.
    """
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS _ct_migrations (
                    key VARCHAR(100) PRIMARY KEY,
                    applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            """))
            conn.commit()

            result = conn.execute(text("SELECT 1 FROM _ct_migrations WHERE key = 'call_tz_utc_to_ist_v1'"))
            if result.fetchone():
                logging.info("[CT-TZ-FIX] ✅ Timezone migration already applied — skipping")
                return

            count_result = conn.execute(text("SELECT COUNT(*) FROM staff_call_logs"))
            total = count_result.fetchone()[0]

            if total > 0:
                conn.execute(text("""
                    UPDATE staff_call_logs
                    SET call_datetime = call_datetime + INTERVAL '5 hours 30 minutes',
                        call_date = TO_CHAR(call_datetime + INTERVAL '5 hours 30 minutes', 'YYYY-MM-DD')
                """))
                logging.info(f"[CT-TZ-FIX] ✅ Fixed timezone for {total} call records (UTC naive → IST naive)")
            else:
                logging.info("[CT-TZ-FIX] ✅ No existing call records — nothing to migrate")

            conn.execute(text("INSERT INTO _ct_migrations (key) VALUES ('call_tz_utc_to_ist_v1')"))
            conn.commit()
    except Exception as e:
        logging.warning(f"[CT-TZ-FIX] Timezone migration failed (non-fatal): {e}")


