def migrate_legacy_wallet_balances():
    """
    DC-WALLET-MIGRATION (Mar 2026): One-time idempotent migration.
    Creates a 'Balance Adjustment' pending_income entry (verification_status=Completed)
    for every user who has a positive withdrawable_wallet in the users table but has
    NO pending_income records at all.  These are pre-DC-Protocol legacy users whose
    balance was written directly to users.withdrawable_wallet before the materialized
    view system was introduced.  After this runs, the user_withdrawable_wallet_balance
    view will reflect their correct balance and the shadow-mode reconciliation will pass.
    Idempotent: if ANY pending_income record already exists for a user, that user is skipped.
    """
    try:
        from sqlalchemy import text as _sql_text
        with engine.connect() as conn:
            # Find all pre-migration users in one query
            legacy_users = conn.execute(_sql_text("""
                SELECT u.id, COALESCE(u.withdrawable_wallet, 0) AS legacy_balance
                FROM "user" u
                WHERE COALESCE(u.withdrawable_wallet, 0) > 0.01
                  AND u.id != 'MNR00000000'
                  AND NOT EXISTS (
                      SELECT 1 FROM pending_income pi WHERE pi.bev_user_id = u.id
                  )
            """)).fetchall()

            if not legacy_users:
                print("[DC-WALLET-MIGRATION] ✅ No legacy wallet users found — nothing to migrate", flush=True)
                return

            now_ist = __import__('datetime').datetime.now()
            migration_date = __import__('datetime').datetime(2025, 1, 1)

            inserted = 0
            for row in legacy_users:
                amt = float(row.legacy_balance)
                conn.execute(_sql_text("""
                    INSERT INTO pending_income (
                        bev_user_id, income_type,
                        gross_amount, admin_deduction, tds_deduction,
                        gurudakshina_deduction, net_amount,
                        withdrawal_wallet_amount, upgraded_wallet_amount,
                        verification_status, tally_status, payment_status,
                        admin_verified_at, super_admin_verified_at, accounts_paid_at,
                        business_date, calculation_timestamp,
                        created_at, updated_at,
                        left_points_consumed, right_points_consumed, pairs_matched,
                        notes
                    ) VALUES (
                        :uid, 'Balance Adjustment',
                        :amt, 0, 0,
                        0, :amt,
                        :amt, 0,
                        'Completed', 'PENDING', 'PAID',
                        :now, :now, :now,
                        :bdate, :now,
                        :now, :now,
                        0, 0, 0,
                        'Pre-migration balance adjustment — wallet balance carried forward from legacy system'
                    )
                """), {
                    "uid": row.id,
                    "amt": amt,
                    "now": now_ist,
                    "bdate": migration_date,
                })
                inserted += 1
                print(f"[DC-WALLET-MIGRATION] ✅ Created adjustment entry for {row.id}: ₹{amt:,.0f}", flush=True)

            conn.commit()
            print(f"[DC-WALLET-MIGRATION] ✅ Migration complete — {inserted} adjustment entries created", flush=True)

    except Exception as e:
        print(f"[DC-WALLET-MIGRATION] ⚠️ Migration failed (non-fatal): {e}", flush=True)


def _safe_run(fn, *args, **kwargs):
    """DC Protocol (Mar 2026): Startup function wrapper that catches BaseException.
    Required because asyncio.CancelledError (BaseException subclass) is NOT caught
    by plain `except Exception` — it would propagate up and crash uvicorn during
    Neon serverless cold-start. Using this wrapper ensures any startup fix function
    failure is logged and skipped rather than taking down the server."""
    try:
        return fn(*args, **kwargs)
    except BaseException as _e:
        logging.error(
            f"[DC-SAFE-RUN] ❌ {fn.__name__} raised {type(_e).__name__}: {_e} "
            f"— server continues in degraded mode"
        )
        return None


def fix_marketplace_image_urls():
    """Convert Google Drive uc?export=view URLs to thumbnail format in marketplace_spares.
    The uc?export=view endpoint returns HTML for unauthenticated requests, causing 415
    errors in the image proxy. The thumbnail endpoint reliably serves images.
    Fixes both image_url (text) and image_data (JSONB) columns."""
    from sqlalchemy import text
    import re
    import json as _json
    uc_pattern = re.compile(r'drive\.google\.com/uc\?(?:export=\w+&)?id=([a-zA-Z0-9_-]+)')
    def _convert_url(url_str):
        m = uc_pattern.search(url_str)
        if m:
            return f'https://drive.google.com/thumbnail?id={m.group(1)}&sz=w800'
        return None
    def _convert_thumb(url_str):
        m = uc_pattern.search(url_str)
        if m:
            return f'https://drive.google.com/thumbnail?id={m.group(1)}&sz=w400'
        return None
    try:
        with engine.connect() as conn:
            rows = conn.execute(text(
                "SELECT id, image_url, image_data::text FROM marketplace_spares "
                "WHERE (image_url IS NOT NULL AND image_url != '' "
                "AND (image_url LIKE '%uc?export=view%' OR image_url LIKE '%uc?id=%')) "
                "OR (image_data::text LIKE '%uc?export=view%' OR image_data::text LIKE '%uc?id=%')"
            )).fetchall()
            if not rows:
                print("[DC-IMG-FIX] No legacy uc?export=view URLs found in marketplace_spares", flush=True)
                return
            updated = 0
            for row_id, image_url, image_data_str in rows:
                changes = {}
                if image_url and uc_pattern.search(image_url):
                    new_url = _convert_url(image_url)
                    if new_url:
                        changes['image_url'] = new_url
                if image_data_str and 'uc?' in (image_data_str or ''):
                    try:
                        img_list = _json.loads(image_data_str) if image_data_str else []
                        modified = False
                        for img in (img_list if isinstance(img_list, list) else []):
                            if isinstance(img, dict):
                                if img.get('url') and uc_pattern.search(img['url']):
                                    new_u = _convert_url(img['url'])
                                    if new_u:
                                        img['url'] = new_u
                                        modified = True
                                if img.get('thumb') and uc_pattern.search(img['thumb']):
                                    new_t = _convert_thumb(img['thumb'])
                                    if new_t:
                                        img['thumb'] = new_t
                                        modified = True
                        if modified:
                            changes['image_data'] = _json.dumps(img_list)
                    except Exception:
                        pass
                if changes:
                    sets = ', '.join(f"{k} = :{k}" for k in changes)
                    changes['id'] = row_id
                    conn.execute(text(f"UPDATE marketplace_spares SET {sets} WHERE id = :id"), changes)
                    updated += 1
            if updated:
                conn.commit()
            print(f"[DC-IMG-FIX] Converted {updated}/{len(rows)} marketplace image URLs to thumbnail format", flush=True)
    except Exception as e:
        print(f"[DC-IMG-FIX] Could not fix marketplace image URLs: {e}", flush=True)


