def create_vgk_promo_tables():
    """DC Protocol Apr 2026: VGK Promo Codes + Redemptions tables."""
    from sqlalchemy import text
    try:
        with engine.connect() as conn:
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS vgk_promo_codes (
                    id SERIAL PRIMARY KEY,
                    code VARCHAR(50) UNIQUE NOT NULL,
                    label VARCHAR(200),
                    promo_type VARCHAR(20) NOT NULL DEFAULT 'GENERAL'
                        CHECK (promo_type IN ('GENERAL','MNR_MEMBER','ETC_STUDENT')),
                    points_credit NUMERIC(12,2) NOT NULL DEFAULT 0,
                    tier_config JSONB,
                    status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE'
                        CHECK (status IN ('ACTIVE','PAUSED','INACTIVE')),
                    valid_from TIMESTAMP,
                    valid_to TIMESTAMP,
                    usage_limit INTEGER,
                    times_used INTEGER NOT NULL DEFAULT 0,
                    company_id INTEGER NOT NULL,
                    created_by INTEGER,
                    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    updated_at TIMESTAMP NOT NULL DEFAULT NOW()
                )
            """))
            conn.execute(text("CREATE INDEX IF NOT EXISTS ix_vpc_status ON vgk_promo_codes(status)"))
            conn.execute(text("CREATE INDEX IF NOT EXISTS ix_vpc_company ON vgk_promo_codes(company_id)"))
            conn.execute(text("CREATE INDEX IF NOT EXISTS ix_vpc_type ON vgk_promo_codes(promo_type)"))
            conn.execute(text("""
                CREATE TABLE IF NOT EXISTS vgk_promo_redemptions (
                    id SERIAL PRIMARY KEY,
                    promo_code_id INTEGER NOT NULL REFERENCES vgk_promo_codes(id) ON DELETE CASCADE,
                    partner_id INTEGER NOT NULL REFERENCES official_partners(id) ON DELETE CASCADE,
                    verified_ref VARCHAR(50),
                    points_awarded NUMERIC(12,2) NOT NULL DEFAULT 0,
                    redeemed_at TIMESTAMP NOT NULL DEFAULT NOW(),
                    notes TEXT,
                    CONSTRAINT uq_vpr_code_partner UNIQUE (promo_code_id, partner_id)
                )
            """))
            conn.execute(text("CREATE INDEX IF NOT EXISTS ix_vpr_partner ON vgk_promo_redemptions(partner_id)"))
            conn.execute(text("CREATE INDEX IF NOT EXISTS ix_vpr_code ON vgk_promo_redemptions(promo_code_id)"))
            conn.commit()
            print("[DC-VGK-PROMO] ✅ vgk_promo_codes / vgk_promo_redemptions tables ready", flush=True)
    except Exception as e:
        print(f"[DC-VGK-PROMO] ⚠️ create_vgk_promo_tables (non-fatal): {e}", flush=True)


