def add_cp_designation_schema():
    """DC_CP_CARD_001 Apr 2026: Add CP designation tier + manual activation flag to official_partners.
    Additive-only — no existing columns altered."""
    from sqlalchemy import text
    cols = [
        ("card_manually_activated", "BOOLEAN NOT NULL DEFAULT FALSE"),
        ("cp_designation_tier",     "VARCHAR(30) NOT NULL DEFAULT 'none'"),
    ]
    try:
        with engine.connect() as conn:
            for col, defn in cols:
                exists = conn.execute(text(
                    "SELECT 1 FROM information_schema.columns "
                    "WHERE table_name='official_partners' AND column_name=:c"
                ), {"c": col}).fetchone()
                if not exists:
                    conn.execute(text(f"ALTER TABLE official_partners ADD COLUMN {col} {defn}"))
                    logging.info(f"[DC-CP-CARD] Added official_partners.{col}")
            conn.commit()
            print("[DC-CP-CARD] ✅ CP designation schema migration complete", flush=True)
    except Exception as e:
        logging.warning(f"[DC-CP-CARD] CP designation migration failed (non-fatal): {e}")


