    # DC Protocol Mar 2026 — FIX C: valid_break_type constraints on staff_realtime_locations
    # Production DB has TWO constraint variants:
    #   "valid_break_type"       — original (uppercase-only, no MEETING/OTHER)
    #   "valid_break_type_check" — our replacement (may already exist from earlier deploy)
    # Drop BOTH old variants, then add a single clean constraint that accepts all uppercase values.
    # Endpoint normalises break_type to .upper() before insert.
    try:
        with engine.connect() as _bc:
            _bc.execute(_text("ALTER TABLE staff_realtime_locations DROP CONSTRAINT IF EXISTS valid_break_type"))
            _bc.execute(_text("ALTER TABLE staff_realtime_locations DROP CONSTRAINT IF EXISTS valid_break_type_check"))
            _bc.execute(_text(
                "ALTER TABLE staff_realtime_locations ADD CONSTRAINT valid_break_type_check "
                "CHECK (break_type IS NULL OR break_type IN "
                "('LUNCH','TEA','PERSONAL','CLIENT_VISIT','TRAVEL','EMERGENCY','MEETING','OTHER'))"
            ))
            _bc.commit()
            print("[DC-STARTUP] ✅ valid_break_type + valid_break_type_check both dropped; clean constraint added", flush=True)
    except Exception as _bc_e:
        print(f"[DC-STARTUP] ⚠️ valid_break_type constraint migration (non-fatal): {_bc_e}", flush=True)

    # DC Protocol Mar 2026 — Task-26: Fix valid_ticket_status CHECK to allow 'Cancelled'
    # The original constraint only listed Open/In Progress/Resolved/Closed.
    # Setting sub_status='cancelled' triggers status='Cancelled' which violated this constraint.
    # Also patch any data rows where status='Open' but sub_status indicates in-progress work.
    try:
        with engine.connect() as _tsc:
            _tsc.execute(_text("ALTER TABLE service_ticket DROP CONSTRAINT IF EXISTS valid_ticket_status"))
            _tsc.execute(_text(
                "ALTER TABLE service_ticket ADD CONSTRAINT valid_ticket_status "
                "CHECK (status IN ('Open', 'In Progress', 'Resolved', 'Closed', 'Cancelled'))"
            ))
            # Patch data integrity: rows with in-progress sub_status but stale 'Open' top-level status
            _tsc.execute(_text(
                "UPDATE service_ticket SET status = 'In Progress' "
                "WHERE status = 'Open' AND sub_status IN "
                "('awaiting_spares','acknowledged','diagnosing','procurement_in_progress','ready_for_work')"
            ))
            _tsc.commit()
            print("[DC-STARTUP] ✅ Task-26: valid_ticket_status constraint updated + data integrity patched", flush=True)
    except Exception as _tsc_e:
        print(f"[DC-STARTUP] ⚠️ Task-26: valid_ticket_status migration (non-fatal): {_tsc_e}", flush=True)

