    # ── DC_DAR_003 (Task #53, May 2026): company-tag service_ticket + staff_attendance_sheets ──
    # The DAR's "Service Tickets" and "Staff Present" rows must be company-scoped.
    # Add a nullable company_id column + index, then back-fill from related tables.
    # Idempotent — every statement is `IF NOT EXISTS` or guarded by `IS NULL`.
    try:
        with engine.begin() as _c:
            _c.execute(_text(
                "ALTER TABLE service_ticket ADD COLUMN IF NOT EXISTS company_id INTEGER "
                "REFERENCES associated_companies(id) ON DELETE SET NULL"
            ))
            _c.execute(_text(
                "CREATE INDEX IF NOT EXISTS idx_service_ticket_company ON service_ticket(company_id)"
            ))
            _c.execute(_text(
                "ALTER TABLE staff_attendance_sheets ADD COLUMN IF NOT EXISTS company_id INTEGER "
                "REFERENCES associated_companies(id) ON DELETE SET NULL"
            ))
            _c.execute(_text(
                "CREATE INDEX IF NOT EXISTS idx_attendance_sheet_company ON staff_attendance_sheets(company_id)"
            ))
            # Back-fill service_ticket.company_id (priority: technician → manager → partner)
            _c.execute(_text("""
                UPDATE service_ticket st SET company_id = se.base_company_id
                FROM staff_employees se
                WHERE st.service_technician_id = se.id
                  AND st.company_id IS NULL
                  AND se.base_company_id IS NOT NULL
            """))
            _c.execute(_text("""
                UPDATE service_ticket st SET company_id = se.base_company_id
                FROM staff_employees se
                WHERE st.service_manager_id = se.id
                  AND st.company_id IS NULL
                  AND se.base_company_id IS NOT NULL
            """))
            _c.execute(_text("""
                UPDATE service_ticket st SET company_id = op.company_id
                FROM official_partners op
                WHERE st.partner_id = op.id
                  AND st.company_id IS NULL
                  AND op.company_id IS NOT NULL
            """))
            # Back-fill staff_attendance_sheets.company_id from employee's home company
            _c.execute(_text("""
                UPDATE staff_attendance_sheets sas SET company_id = se.base_company_id
                FROM staff_employees se
                WHERE sas.employee_id = se.id
                  AND sas.company_id IS NULL
                  AND se.base_company_id IS NOT NULL
            """))
        print("[DC_DAR_003] ✅ service_ticket + staff_attendance_sheets company_id ensured + back-filled", flush=True)
    except Exception as _e:
        print(f"[DC_DAR_003] ⚠️ {_e}", flush=True)

    # ── Marketplace auto-sync (starts its own sub-thread with 8s delay) ──────
    # DC Protocol: advisory lock (id=8877) prevents all 4 uvicorn workers from
    # running the sync simultaneously and hitting lock-contention timeouts on Neon.
    _MARKET_SYNC_LOCK_ID = 8877
    def _auto_sync_marketplace_if_empty():
        import threading as _t2
        def _do_sync():
            time.sleep(8)
            from app.core.database import SessionLocal as _SL
            _db2 = _SL()
            _lock_held = False
            try:
                _got = _db2.execute(_text(
                    "SELECT pg_try_advisory_lock(:lid)"
                ), {"lid": _MARKET_SYNC_LOCK_ID}).scalar()
                if not _got:
                    logging.info("[DC-MARKET-SYNC] Another worker holds the sync lock — skipping")
                    return
                _lock_held = True
                from app.services.marketplace_sync import run_sync as _run_sync
                row = _db2.execute(_text(
                    "SELECT COUNT(*) FROM marketplace_spares WHERE is_active = TRUE AND segment_id IS NOT NULL"
                )).scalar()
                if row == 0:
                    logging.info("[DC-MARKET-SYNC] No segmented products — running startup sync from Google Sheet...")
                    result = _run_sync(_db2, company_id=1, triggered_by='startup_auto')
                    logging.info(f"[DC-MARKET-SYNC] Startup sync: {result.get('success_count', 0)} products loaded")
                else:
                    logging.info(f"[DC-MARKET-SYNC] {row} segmented products in DB — startup sync skipped")
            except Exception as _e2:
                logging.warning(f"[DC-MARKET-SYNC] Startup auto-sync error: {_e2}")
            finally:
                if _lock_held:
                    try:
                        _db2.execute(_text("SELECT pg_advisory_unlock(:lid)"), {"lid": _MARKET_SYNC_LOCK_ID})
                        _db2.commit()
                    except Exception:
                        pass
                _db2.close()
        _t2.Thread(target=_do_sync, daemon=True, name="marketplace-startup-sync").start()

    _auto_sync_marketplace_if_empty()

