    # ── DC Protocol Mar 2026: VGK Paid/Non-Paid activation split ─────────────────
    # DC Protocol Mar 2026 (updated Apr 2026):
    # Commission rates confirmed by user:
    #   Solar Activated:  L1=2.5% L2=0.75% L3=0.25% L4=1.5%
    #   Solar Registered: L1=1.5% L2=0%    L3=0%    L4=1.0%
    #   EV B2B Activated: L1=1.0% L2=2.5%  L3=1.5%  L4=3.0% (1% lifetime)
    #   EV B2C Activated: L1=5.0% L2=2.5%  L3=1.5%  L4=3.0%
    #   EV Reg (both):    L1=2.0% L2=0%    L3=0%    L4=1.0%
    try:
        with engine.connect() as _vc:
            _vc.execute(text("SET statement_timeout = 0"))

            # 1. Add is_paid_activation to official_partners (idempotent)
            try:
                _vc.execute(text("ALTER TABLE official_partners ADD COLUMN IF NOT EXISTS is_paid_activation BOOLEAN NOT NULL DEFAULT FALSE"))
                _vc.commit()
            except Exception as _e:
                if 'already exists' not in str(_e).lower():
                    print(f"[DC-VGK-PAID] ⚠️ is_paid_activation col: {_e}", flush=True)
                _vc.rollback()

            # 2. Add is_paid_member to vgk_team_commission_config (idempotent)
            try:
                _vc.execute(text("ALTER TABLE vgk_team_commission_config ADD COLUMN IF NOT EXISTS is_paid_member BOOLEAN NOT NULL DEFAULT TRUE"))
                _vc.commit()
            except Exception as _e:
                if 'already exists' not in str(_e).lower():
                    print(f"[DC-VGK-PAID] ⚠️ is_paid_member col: {_e}", flush=True)
                _vc.rollback()

            # 3. Drop old unique constraints and recreate with is_paid_member (idempotent)
            for _old_cname in [
                'uq_vgk_config_company_category',
                'vgk_team_commission_config_company_id_category_id_key',
            ]:
                try:
                    _vc.execute(text(f"ALTER TABLE vgk_team_commission_config DROP CONSTRAINT IF EXISTS {_old_cname}"))
                    _vc.commit()
                except Exception as _e:
                    print(f"[DC-VGK-PAID] ⚠️ drop old unique {_old_cname}: {_e}", flush=True)
                    _vc.rollback()
            try:
                _vc.execute(text("ALTER TABLE vgk_team_commission_config ADD CONSTRAINT uq_vgk_config_company_category_paid UNIQUE (company_id, category_id, is_paid_member)"))
                _vc.commit()
            except Exception as _e:
                if 'already exists' not in str(_e).lower():
                    print(f"[DC-VGK-PAID] ⚠️ add new unique: {_e}", flush=True)
                _vc.rollback()

            # 4. One-time only: stamp legacy rows as paid IF no non-paid rows exist yet
            #    Guard prevents this from flipping user-inserted non-paid rows on every restart.
            try:
                _nonpaid_count = _vc.execute(text(
                    "SELECT COUNT(*) FROM vgk_team_commission_config WHERE is_paid_member = FALSE"
                )).scalar()
                if _nonpaid_count == 0:
                    _vc.execute(text(
                        "UPDATE vgk_team_commission_config SET is_paid_member = TRUE "
                        "WHERE is_paid_member IS NULL"
                    ))
                    _vc.commit()
                    print("[DC-VGK-PAID] ✅ Step 4: NULL is_paid_member stamped TRUE (one-time only)", flush=True)
                else:
                    print(f"[DC-VGK-PAID] ✅ Step 4: Skipped (non-paid rows exist: {_nonpaid_count})", flush=True)
            except Exception as _e:
                print(f"[DC-VGK-PAID] ⚠️ step 4 guard: {_e}", flush=True)
                _vc.rollback()

            # 5a. Upsert Solar Activated rates: L1=2.5 L2=0.75 L3=0.25 L4=1.5
            try:
                _vc.execute(text("""
                    UPDATE vgk_team_commission_config vtc
                    SET level1_pct = 2.5, level2_pct = 0.75, level3_pct = 0.25, level4_pct = 1.5
                    FROM signup_categories sc
                    WHERE vtc.category_id = sc.id
                      AND LOWER(sc.name) = 'solar'
                      AND vtc.is_paid_member = TRUE
                """))
                _vc.commit()
            except Exception as _e:
                print(f"[DC-VGK-PAID] ⚠️ update paid solar rates: {_e}", flush=True)
                _vc.rollback()

            # 5b. Upsert EV B2B Activated rates: L1=1.0 L2=2.5 L3=1.5 L4=3.0 (1% lifetime)
            try:
                _vc.execute(text("""
                    UPDATE vgk_team_commission_config vtc
                    SET level1_pct = 1.0, level2_pct = 2.5, level3_pct = 1.5, level4_pct = 3.0
                    FROM signup_categories sc
                    WHERE vtc.category_id = sc.id
                      AND LOWER(sc.name) = 'ev b2b'
                      AND vtc.is_paid_member = TRUE
                """))
                _vc.commit()
            except Exception as _e:
                print(f"[DC-VGK-PAID] ⚠️ update paid ev b2b rates: {_e}", flush=True)
                _vc.rollback()

            # 5c. Upsert EV B2C Activated rates: L1=5.0 L2=2.5 L3=1.5 L4=3.0
            try:
                _vc.execute(text("""
                    UPDATE vgk_team_commission_config vtc
                    SET level1_pct = 5.0, level2_pct = 2.5, level3_pct = 1.5, level4_pct = 3.0
                    FROM signup_categories sc
                    WHERE vtc.category_id = sc.id
                      AND LOWER(sc.name) = 'ev b2c'
                      AND vtc.is_paid_member = TRUE
                """))
                _vc.commit()
            except Exception as _e:
                print(f"[DC-VGK-PAID] ⚠️ update paid ev b2c rates: {_e}", flush=True)
                _vc.rollback()

            # 6. Upsert Registered (non-paid) rows per category per company
            #    Solar: L1=1.5 L4=1.0; EV (B2B+B2C): L1=2.0 L4=1.0; others: L1=1.0
            try:
                _vc.execute(text("""
                    INSERT INTO vgk_team_commission_config
                        (company_id, category_id, is_paid_member,
                         level1_pct, level1_type, level1_amt,
                         level2_pct, level2_type, level2_amt,
                         level3_pct, level3_type, level3_amt,
                         level4_pct, level4_type, level4_amt,
                         monthly_target, bonus_pct, markup_pct, is_active,
                         created_at, updated_at)
                    SELECT vtc.company_id, vtc.category_id, FALSE,
                           CASE WHEN LOWER(sc.name) = 'solar'  THEN 1.5
                                WHEN LOWER(sc.name) LIKE 'ev b%' THEN 2.0
                                ELSE 1.0 END,
                           'PCT', 0,
                           0, 'PCT', 0,
                           0, 'PCT', 0,
                           CASE WHEN LOWER(sc.name) IN ('solar','ev b2b','ev b2c') THEN 1.0
                                ELSE 0 END,
                           'PCT', 0,
                           0, 0, 0, TRUE,
                           NOW(), NOW()
                    FROM vgk_team_commission_config vtc
                    JOIN signup_categories sc ON sc.id = vtc.category_id
                    WHERE vtc.is_paid_member = TRUE
                    ON CONFLICT (company_id, category_id, is_paid_member) DO NOTHING
                """))
                _vc.commit()
            except Exception as _e:
                print(f"[DC-VGK-PAID] ⚠️ insert non-paid rows: {_e}", flush=True)
                _vc.rollback()

        print("[DC-STARTUP] ✅ VGK paid/non-paid split migration complete (Apr 2026 rates)", flush=True)
    except Exception as _vgk_paid_err:
        print(f"[DC-STARTUP] ⚠️ VGK paid/non-paid migration (non-fatal): {_vgk_paid_err}", flush=True)

