    # DC-BILLING-RECALC: Fix any billings whose net_payable is stale (doesn't match sum of items)
    try:
        _recalc_sql = text("""
            UPDATE service_ticket_billing b
            SET
                taxable_amount = COALESCE(item_totals.taxable, 0),
                total_amount   = COALESCE(item_totals.total, 0),
                net_payable    = COALESCE(item_totals.total, 0)
                                 - COALESCE(b.discount_amount, 0)
                                 - COALESCE(b.manual_discount_amount, 0)
                                 + COALESCE(b.round_off, 0),
                amount_due     = COALESCE(item_totals.total, 0)
                                 - COALESCE(b.discount_amount, 0)
                                 - COALESCE(b.manual_discount_amount, 0)
                                 + COALESCE(b.round_off, 0)
                                 - COALESCE(b.amount_paid, 0)
            FROM (
                SELECT billing_id,
                       SUM(taxable_amount)                                    AS taxable,
                       SUM(COALESCE(taxable_amount,0)
                           + COALESCE(cgst_amount,0)
                           + COALESCE(sgst_amount,0)
                           + COALESCE(igst_amount,0))                         AS total
                FROM service_ticket_billing_item
                GROUP BY billing_id
            ) item_totals
            WHERE b.id = item_totals.billing_id
              AND b.status = 'draft'
              AND ABS(b.total_amount - item_totals.total) > 0.01
        """)
        with engine.begin() as _c:
            _res = _c.execute(_recalc_sql)
            _fixed = _res.rowcount
        if _fixed:
            print(f"[DC-BILLING-RECALC] ✅ Recalculated {_fixed} stale draft billing(s)", flush=True)
    except Exception as _rce:
        print(f"[DC-BILLING-RECALC] Warning: {_rce}", flush=True)

