    # DC_VGK_POINTS_CORRECTION_001 (runs FIRST — must precede backfill)
    # Fixes non-paid members whose vgk_points_balance exceeds 10,000 due to the old repeated
    # MANUAL_ADJUSTMENT backfill bug OR parallel-worker race conditions on WELCOME_BONUS inserts.
    # Uses pg_try_advisory_xact_lock so only ONE of the 4 uvicorn workers executes this block.
    # Detects excess via actual balance check (not ledger reason codes, which may be duplicated).
    try:
        with engine.begin() as _c:
            _got_lock = _c.execute(text("SELECT pg_try_advisory_xact_lock(88880001)")).scalar()
            if _got_lock:
                # DC-BONANZA-SUBMITDATE-001 (Jun 2026): The cap only applies to bonus/
                # promotional points (WELCOME, CAMPAIGN, REFERRAL, SIGNUP).  Points earned
                # from actual business (INCOME_EARNED — solar advances, commissions, slab
                # bonuses) must never be removed — they represent real partner earnings.
                _bad_rows = _c.execute(text("""
                    SELECT op.id, op.partner_code, op.vgk_points_balance,
                           COALESCE(SUM(CASE WHEN pl.reason_code = 'CAMPAIGN_BONUS'
                                             THEN pl.points_credit ELSE 0 END), 0) AS camp,
                           COALESCE(SUM(CASE WHEN pl.reason_code IN ('REFERRAL_BONUS','SIGNUP_BONUS')
                                             THEN pl.points_credit ELSE 0 END), 0) AS ref_bonus,
                           COALESCE(SUM(CASE WHEN pl.reason_code = 'INCOME_EARNED'
                                             THEN pl.points_credit - pl.points_debit ELSE 0 END), 0) AS net_income
                    FROM official_partners op
                    LEFT JOIN vgk_points_ledger pl ON pl.partner_id = op.id
                    WHERE op.category = 'VGK_TEAM'
                      AND op.is_paid_activation = FALSE
                      AND op.vgk_points_balance > 10000
                    GROUP BY op.id, op.partner_code, op.vgk_points_balance
                """)).fetchall()
                _cx = 0
                for (_pid, _pcode, _pbal, _camp, _ref_bonus, _net_income) in _bad_rows:
                    # Correct cap = 10,000 welcome + campaign + referral/signup + earned income
                    _correct_bal = 10000 + float(_camp) + float(_ref_bonus) + max(0.0, float(_net_income))
                    _excess = float(_pbal or 0) - _correct_bal
                    if _excess <= 0:
                        continue
                    # Debit the excess so net balance = correct_bal
                    _c.execute(text(
                        "INSERT INTO vgk_points_ledger "
                        "(partner_id, points_credit, points_debit, balance_after, reason_code, notes, created_at) "
                        "VALUES (:pid, 0, :deb, :cb, 'MANUAL_ADJUSTMENT', :notes, NOW())"
                    ), {
                        "pid": _pid, "deb": int(_excess), "cb": _correct_bal,
                        "notes": f"DC_VGK_POINTS_CORRECTION_001 — removed {int(_excess)} excess pts (balance was {int(float(_pbal))})"
                    })
                    _c.execute(text(
                        "UPDATE official_partners SET vgk_points_balance=:cb WHERE id=:pid"
                    ), {"cb": _correct_bal, "pid": _pid})
                    _cx += 1
                if _cx:
                    print(f"[DC_VGK_POINTS_CORRECTION_001] ✅ Corrected {_cx} member(s) with excess points → capped at 10,000 + campaign + referral", flush=True)
                else:
                    print(f"[DC_VGK_POINTS_CORRECTION_001] ✅ No excess point corrections needed", flush=True)
            else:
                print(f"[DC_VGK_POINTS_CORRECTION_001] ✅ skipped (concurrent worker)", flush=True)
    except Exception as _e:
        print(f"[DC_VGK_POINTS_CORRECTION_001] ⚠️ {_e}", flush=True)

    # DC_VGK_POINTS_BACKFILL_002: Top up members missing their baseline bonus.
    # Runs AFTER correction so corrected members already have correct balance and won't be double-topped.
    # Uses pg_try_advisory_xact_lock(88880002) — only ONE worker processes backfill per restart.
    # Non-paid check uses vgk_points_balance < 10000 (not SUM of ledger entries) to avoid racing.
    try:
        with engine.begin() as _c:
            _got_lock = _c.execute(text("SELECT pg_try_advisory_xact_lock(88880002)")).scalar()
            if _got_lock:
                # --- Paid members: ensure 50,000 total activation bonus ---
                _paid_rows = _c.execute(text("""
                    SELECT op.id, op.partner_code, op.vgk_points_balance,
                           COALESCE(SUM(CASE WHEN pl.reason_code IN ('ACTIVATION_BONUS','LOYAL_BONUS')
                                             THEN pl.points_credit ELSE 0 END), 0) AS act_total
                    FROM official_partners op
                    LEFT JOIN vgk_points_ledger pl ON pl.partner_id = op.id
                    WHERE op.category = 'VGK_TEAM' AND op.is_paid_activation = TRUE
                    GROUP BY op.id, op.partner_code, op.vgk_points_balance
                    HAVING COALESCE(SUM(CASE WHEN pl.reason_code IN ('ACTIVATION_BONUS','LOYAL_BONUS')
                                             THEN pl.points_credit ELSE 0 END), 0) < 50000
                """)).fetchall()
                _b1 = 0
                for (_pid, _pcode, _pbal, _act_total) in _paid_rows:
                    _top_up = int(50000 - float(_act_total))
                    if _top_up <= 0:
                        continue
                    _new_bal = float(_pbal or 0) + _top_up
                    _c.execute(text(
                        "INSERT INTO vgk_points_ledger "
                        "(partner_id, points_credit, points_debit, balance_after, reason_code, reference_type, notes, created_at) "
                        "VALUES (:pid, :cr, 0, :bal, 'ACTIVATION_BONUS', 'activation', :notes, NOW())"
                    ), {
                        "pid": _pid, "cr": _top_up, "bal": _new_bal,
                        "notes": f"DC_VGK_POINTS_BACKFILL_002 — activation top-up +{_top_up} pts for {_pcode}"
                    })
                    _c.execute(text(
                        "UPDATE official_partners SET vgk_points_balance=:bal WHERE id=:pid"
                    ), {"bal": _new_bal, "pid": _pid})
                    _b1 += 1

                # --- Non-paid members: ensure exactly 10,000 base bonus credits ---
                # Guard uses SUM of bonus ledger credits (WELCOME_BONUS + CAMPAIGN_BONUS),
                # NOT raw vgk_points_balance, so that legitimate VCI income debits
                # (which reduce balance) do NOT trigger spurious welcome top-ups.
                _reg_rows = _c.execute(text("""
                    SELECT op.id, op.partner_code, op.vgk_points_balance,
                           COALESCE(SUM(CASE WHEN pl.reason_code IN ('WELCOME_BONUS','CAMPAIGN_BONUS')
                                             THEN pl.points_credit ELSE 0 END), 0) AS bonus_total
                    FROM official_partners op
                    LEFT JOIN vgk_points_ledger pl ON pl.partner_id = op.id
                    WHERE op.category = 'VGK_TEAM'
                      AND op.is_paid_activation = FALSE
                    GROUP BY op.id, op.partner_code, op.vgk_points_balance
                    HAVING COALESCE(SUM(CASE WHEN pl.reason_code IN ('WELCOME_BONUS','CAMPAIGN_BONUS')
                                             THEN pl.points_credit ELSE 0 END), 0) < 10000
                """)).fetchall()
                _b2 = 0
                for (_pid, _pcode, _pbal, _bonus_total) in _reg_rows:
                    _top_up = int(10000 - float(_bonus_total or 0))
                    if _top_up <= 0:
                        continue
                    _new_bal_r = float(_pbal or 0) + _top_up
                    _c.execute(text(
                        "INSERT INTO vgk_points_ledger "
                        "(partner_id, points_credit, points_debit, balance_after, reason_code, reference_type, notes, created_at) "
                        "VALUES (:pid, :cr, 0, :bal, 'WELCOME_BONUS', 'signup', :notes, NOW())"
                    ), {
                        "pid": _pid, "cr": _top_up, "bal": _new_bal_r,
                        "notes": f"DC_VGK_POINTS_BACKFILL_002 — welcome top-up +{_top_up} pts for {_pcode}"
                    })
                    _c.execute(text(
                        "UPDATE official_partners SET vgk_points_balance=:bal WHERE id=:pid"
                    ), {"bal": _new_bal_r, "pid": _pid})
                    _b2 += 1

                print(f"[DC_VGK_POINTS_BACKFILL_002] ✅ Topped-up {_b1} paid (activation→50k) + {_b2} non-paid (welcome→10k) members", flush=True)
            else:
                print(f"[DC_VGK_POINTS_BACKFILL_002] ✅ skipped (concurrent worker)", flush=True)
    except Exception as _e:
        print(f"[DC_VGK_POINTS_BACKFILL_002] ⚠️ {_e}", flush=True)

    # DC_VGK_ROOT_ACTIVATE_001: Ensure VGK07102207 (root/support member) is fully activated
    # with 55,000 points. Idempotent — only runs correction if needed.
    try:
        with engine.begin() as _c:
            _root = _c.execute(text(
                "SELECT id, is_active, is_paid_activation, vgk_points_balance "
                "FROM official_partners WHERE partner_code='VGK07102207' AND category='VGK_TEAM' LIMIT 1"
            )).fetchone()
            if _root:
                _root_id, _r_active, _r_paid, _r_pts = _root
                _pts_float = float(_r_pts or 0)
                # Only trigger a fix if activation flags are wrong OR balance is below floor.
                # Never reset downward — members may have earned points above 55,000 legitimately.
                _needs_fix = (not _r_active) or (not _r_paid) or (_pts_float < 55000.0)
                if _needs_fix:
                    from datetime import datetime as _dt
                    _now = _dt.now()
                    if _pts_float < 55000.0:
                        _credit = int(55000 - _pts_float)
                        _c.execute(text(
                            "INSERT INTO vgk_points_ledger "
                            "(partner_id, points_credit, points_debit, balance_after, reason_code, notes, created_at) "
                            "VALUES (:pid, :cr, 0, 55000, 'MANUAL_ADJUSTMENT', "
                            "'DC_VGK_ROOT_ACTIVATE_001 — root member corrected to 55,000 pts', :now)"
                        ), {"pid": _root_id, "cr": _credit, "now": _now})
                    _c.execute(text(
                        "UPDATE official_partners "
                        "SET is_active=true, is_paid_activation=true, "
                        "vgk_points_balance=GREATEST(vgk_points_balance, 55000), "
                        "vgk_activated_at=COALESCE(vgk_activated_at, :now), updated_at=:now "
                        "WHERE id=:pid"
                    ), {"pid": _root_id, "now": _now})
                    print("[DC_VGK_ROOT_ACTIVATE_001] ✅ VGK07102207 corrected: activated + 55,000 pts floor", flush=True)
                else:
                    print("[DC_VGK_ROOT_ACTIVATE_001] ✅ VGK07102207 already correct — skipping", flush=True)
            else:
                print("[DC_VGK_ROOT_ACTIVATE_001] ⚠️ VGK07102207 not found — skipping", flush=True)
    except Exception as _e:
        print(f"[DC_VGK_ROOT_ACTIVATE_001] ⚠️ {_e}", flush=True)

