    # DC_VGK_LEDGER_RECONCILE_001: Reconcile vgk_points_ledger for any member where
    # the sum of ledger entries doesn't match their actual vgk_points_balance.
    # Writes a single ACTIVATION_BONUS reconciliation entry for the gap. Idempotent.
    try:
        with engine.begin() as _c:
            _members = _c.execute(text(
                "SELECT id, partner_code, vgk_points_balance FROM official_partners "
                "WHERE category='VGK_TEAM' AND vgk_points_balance > 0"
            )).fetchall()
            _reconciled = 0
            for _m_id, _m_code, _m_bal in _members:
                _m_bal_f = float(_m_bal or 0)
                _ledger = _c.execute(text(
                    "SELECT COALESCE(SUM(points_credit),0) - COALESCE(SUM(points_debit),0) "
                    "FROM vgk_points_ledger WHERE partner_id = :pid"
                ), {"pid": _m_id}).scalar()
                _ledger_net = float(_ledger or 0)
                _gap = round(_m_bal_f - _ledger_net, 2)
                if _gap > 0.01:
                    from datetime import datetime as _dt2
                    _c.execute(text(
                        "INSERT INTO vgk_points_ledger "
                        "(partner_id, points_credit, points_debit, balance_after, reason_code, "
                        "reference_type, notes, created_at) "
                        "VALUES (:pid, :cr, 0, :bal, 'ACTIVATION_BONUS', 'activation', "
                        ":notes, :now)"
                    ), {
                        "pid": _m_id, "cr": _gap, "bal": _m_bal_f,
                        "notes": f"DC_VGK_LEDGER_RECONCILE_001 — ledger gap reconciled for {_m_code} (+{_gap} pts)",
                        "now": _dt2.now()
                    })
                    _reconciled += 1
            print(f"[DC_VGK_LEDGER_RECONCILE_001] ✅ Reconciled {_reconciled} member ledger(s)", flush=True)
    except Exception as _e:
        print(f"[DC_VGK_LEDGER_RECONCILE_001] ⚠️ {_e}", flush=True)

