    # DC-VGK-SLAB-VCI-SYNC-001: One-time backfill — update existing ADVANCE VCI entries
    # whose commission_amount is missing the slab bonus (created before DC-FIX-SLAB-VCI-SYNC-001).
    # Joins vgk_solar_cibil_advances to get advance_amount + slab_bonus_amount per entry.
    # Idempotent via dc_migrations key — safe to run on every restart.
    try:
        _mig_key_slab = 'dc_vgk_slab_vci_sync_20260615'
        with engine.begin() as _c:
            _done = _mig_key_slab in _applied_keys
            if not _done:
                _res = _c.execute(text("""
                    UPDATE vgk_cash_income_entries e
                       SET commission_amount = a.advance_amount + a.slab_bonus_amount,
                           admin_charges     = ROUND((a.advance_amount + a.slab_bonus_amount) * 0.08, 2),
                           tds_amount        = ROUND((a.advance_amount + a.slab_bonus_amount) * 0.02, 2),
                           net_payout        = ROUND((a.advance_amount + a.slab_bonus_amount) * 0.90, 2),
                           updated_at        = NOW()
                      FROM vgk_solar_cibil_advances a
                     WHERE a.partner_id        = e.partner_id
                       AND a.lead_id           = e.source_lead_id
                       AND a.slab_bonus_paid   = TRUE
                       AND a.slab_bonus_amount > 0
                       AND e.kind              = 'ADVANCE'
                       AND e.commission_amount < (a.advance_amount + a.slab_bonus_amount)
                """))
                _c.execute(text("INSERT INTO dc_migrations(key) VALUES(:k)"), {"k": _mig_key_slab})
                print(f"[DC-VGK-SLAB-VCI-SYNC-001] ✅ VCI slab backfill: {_res.rowcount} entries updated", flush=True)
    except Exception as _e:
        print(f"[DC-VGK-SLAB-VCI-SYNC-001] Note: {_e}", flush=True)

    # DC-SENIOR-COMM-BACKFILL-001: Create missing SENIOR_COMM (₹500) entries for advances
    # from Jun 9 2026 onwards that were released before the date-guard removal.
    # Idempotent: skips per-advance if SENIOR_COMM already exists for that source_lead_id.
    try:
        _mig_key_sc = 'dc_senior_comm_backfill_20260615'
        with engine.begin() as _c:
            _done2 = _mig_key_sc in _applied_keys
            if not _done2:
                _adv_rows = _c.execute(text("""
                    SELECT e.id, e.source_lead_id, e.partner_id, e.company_id, e.entry_number,
                           p.parent_partner_id
                      FROM vgk_cash_income_entries e
                      JOIN official_partners p ON p.id = e.partner_id
                     WHERE e.kind   = 'ADVANCE'
                       AND e.status IN ('RELEASED','STAGE1_APPROVED','PAID')
                       AND p.parent_partner_id IS NOT NULL
                       AND e.source_lead_id IS NOT NULL
                       AND e.created_at >= '2026-06-09'
                """)).fetchall()
                _created = 0
                for _adv in _adv_rows:
                    _exists = _c.execute(text("""
                        SELECT 1 FROM vgk_cash_income_entries
                        WHERE partner_id    = :sid
                          AND source_lead_id = :lid
                          AND kind          = 'SENIOR_COMM'
                        LIMIT 1
                    """), {'sid': _adv.parent_partner_id, 'lid': _adv.source_lead_id}).fetchone()
                    if _exists:
                        continue
                    _ts  = datetime.now().strftime('%y%m')
                    _seq = _c.execute(text(
                        "SELECT COUNT(*)+1 FROM vgk_cash_income_entries "
                        "WHERE kind='SENIOR_COMM' AND entry_number LIKE :pfx"
                    ), {'pfx': f'VSCC-{_ts}-%'}).scalar() or 1
                    _c.execute(text("""
                        INSERT INTO vgk_cash_income_entries
                            (company_id, entry_number, partner_id, source_lead_id,
                             category_id, level, deal_value_total, deal_value_excl_tax,
                             commission_pct, commission_amount, admin_charges, tds_amount,
                             net_payout, points_debit_required, points_actually_debited,
                             kind, status, notes, ledger_posted, created_at, updated_at)
                        VALUES
                            (:co, :en, :pid, :lid,
                             NULL, 2, 0, 0,
                             0, 500, 40, 10,
                             450, 0, 0,
                             'SENIOR_COMM', 'PENDING',
                             :notes, FALSE, NOW(), NOW())
                    """), {
                        'co':    _adv.company_id or 4,
                        'en':    f'VSCC-{_ts}-{int(_seq):04d}',
                        'pid':   _adv.parent_partner_id,
                        'lid':   _adv.source_lead_id,
                        'notes': (
                            f'DC-SENIOR-COMM-BACKFILL-001: ₹500 advance incentive — '
                            f'junior advance {_adv.entry_number}'
                        ),
                    })
                    _created += 1
                _c.execute(text("INSERT INTO dc_migrations(key) VALUES(:k)"), {"k": _mig_key_sc})
                print(f"[DC-SENIOR-COMM-BACKFILL-001] ✅ Created {_created} senior comm entries", flush=True)
    except Exception as _e:
        print(f"[DC-SENIOR-COMM-BACKFILL-001] Note: {_e}", flush=True)

    # DC-NO-RELEASE-001: Migrate all RELEASED VCI entries to PENDING so they appear
