    # DC-BONANZA-PAY-FLOW-FIX-001: Reverse premature wallet credits for Payment Released bonanzas.
    # Old code credited wallet at Payment Released; new code waits until staff records actual Paid.
    try:
        _db_fix = SessionLocal()
        try:
            _affected = _db_fix.execute(text("""
                SELECT bp.id AS claim_id, bp.partner_id
                FROM bonanza_progress bp
                WHERE bp.processed_status = 'Payment Released'
                  AND bp.reward_given = true
                  AND EXISTS (
                    SELECT 1 FROM vgk_wallet_transactions
                    WHERE ref_type = 'bonanza_progress' AND ref_id = bp.id
                  )
            """)).fetchall()
            _count = 0
            for _arow in _affected:
                _cid, _pid = _arow.claim_id, _arow.partner_id
                _db_fix.execute(text(
                    "DELETE FROM vgk_wallet_transactions WHERE ref_type='bonanza_progress' AND ref_id=:cid"
                ), {'cid': _cid})
                _db_fix.execute(text("""
                    UPDATE official_partners
                    SET vgk_cash_wallet = (
                        SELECT COALESCE(SUM(CASE WHEN direction='CR' THEN amount ELSE -amount END), 0)
                        FROM vgk_wallet_transactions WHERE partner_id = :pid
                    ),
                    vgk_cash_earned_total = 0
                    WHERE id = :pid
                """), {'pid': _pid})
                _db_fix.execute(text("""
                    UPDATE bonanza_progress SET reward_given=false, reward_given_date=null WHERE id=:cid
                """), {'cid': _cid})
                _count += 1
            _db_fix.commit()
            print(f"[DC-BONANZA-PAY-FLOW-FIX-001] ✅ Reversed {_count} premature wallet credits (Payment Released → awaiting Paid)", flush=True)
        finally:
            _db_fix.close()
    except Exception as _fix_e:
        print(f"[DC-BONANZA-PAY-FLOW-FIX-001] ⚠️ {_fix_e}", flush=True)

