    # DC-PI-DATE-FIX-001: Fix party_ledger transaction_dates for purchase invoice VENDOR_TXN
    # CREDIT entries where the date was set to upload/confirmation date instead of vendor_invoice_date.
    # Root cause: invoices confirmed before vendor_invoice_date was populated defaulted to today.
    # This caused journal entries (posted on actual invoice dates) to not net against their
    # matching purchase invoices in the party ledger, creating a misleading outstanding balance.
    # Fix: align both party_ledger.transaction_date and vendor_transaction_header.transaction_date
    # to the actual vendor_invoice_date from purchase_invoice_uploads.
    try:
        with engine.begin() as _pifix:
            # Fix party_ledger entries first
            _pifix.execute(text("""
                UPDATE party_ledger pl
                SET transaction_date = piu.vendor_invoice_date
                FROM vendor_transaction_header vth
                JOIN purchase_invoice_uploads piu ON piu.vendor_transaction_id = vth.id
                WHERE pl.reference_type = 'VENDOR_TXN'
                  AND pl.reference_id = vth.id
                  AND pl.entry_type = 'CREDIT'
                  AND piu.vendor_invoice_date IS NOT NULL
                  AND pl.transaction_date <> piu.vendor_invoice_date
            """))
            # Also align vendor_transaction_header.transaction_date
            _pifix.execute(text("""
                UPDATE vendor_transaction_header vth
                SET transaction_date = piu.vendor_invoice_date
                FROM purchase_invoice_uploads piu
                WHERE piu.vendor_transaction_id = vth.id
                  AND piu.vendor_invoice_date IS NOT NULL
                  AND vth.transaction_date <> piu.vendor_invoice_date
            """))
        print("[DC-PI-DATE-FIX-001] ✅ party_ledger + VTH transaction_dates aligned to vendor_invoice_date", flush=True)
    except Exception as _pifix_e:
        print(f"[DC-PI-DATE-FIX-001] ⚠️ (non-fatal) {_pifix_e}", flush=True)

