    # DC_CONSOLIDATED_CLEANUP_048 (Task #48, May 2026):
    # Remove legacy CONSOLIDATED_BALANCE_SHEET / _PL / _SALES / _PURCHASES rows
    # left over from prior startup runs. Task #47 collapsed those four pages
    # into a single tabbed page at /staff/consolidated registered as
    # CONSOLIDATED_REPORTS. The legacy rows now point at 404 routes and
    # surface dead entries in the menu access matrix UI. Idempotent.
    try:
        with engine.begin() as _c:
            _legacy_codes = (
                'CONSOLIDATED_BALANCE_SHEET',
                'CONSOLIDATED_PL',
                'CONSOLIDATED_SALES',
                'CONSOLIDATED_PURCHASES',
            )
            _legacy_routes = (
                '/staff/consolidated-balance-sheet',
                '/staff/consolidated-pl',
                '/staff/consolidated-sales',
                '/staff/consolidated-purchases',
            )
            # 1. Redirect per-employee grants from legacy → CONSOLIDATED_REPORTS
            #    (per company, skipping rows that would conflict with an
            #    existing grant for the new menu).
            _c.execute(text("""
                UPDATE staff_employee_menu_settings sems
                   SET menu_id = new_master.id,
                       updated_at = NOW()
                  FROM staff_menu_master old_master
                  JOIN staff_menu_master new_master
                    ON new_master.company_id = old_master.company_id
                   AND new_master.menu_code = 'CONSOLIDATED_REPORTS'
                 WHERE sems.menu_id = old_master.id
                   AND old_master.menu_code = ANY(:codes)
                   AND NOT EXISTS (
                       SELECT 1 FROM staff_employee_menu_settings ex
                        WHERE ex.employee_id = sems.employee_id
                          AND ex.menu_id = new_master.id
                   )
            """), {"codes": list(_legacy_codes)})
            # 2. Delete remaining grants referencing legacy master rows.
            _c.execute(text("""
                DELETE FROM staff_employee_menu_settings
                 WHERE menu_id IN (
                     SELECT id FROM staff_menu_master
                      WHERE menu_code = ANY(:codes)
                 )
            """), {"codes": list(_legacy_codes)})
            # 3. Drop per-company master rows for legacy codes.
            _c.execute(text("""
                DELETE FROM staff_menu_master WHERE menu_code = ANY(:codes)
            """), {"codes": list(_legacy_codes)})
            # 4. Drop role-based access entries for legacy routes.
            _c.execute(text("""
                DELETE FROM staff_role_menu_access WHERE route_path = ANY(:routes)
            """), {"routes": list(_legacy_routes)})
            # 5. Drop global registry rows for legacy codes.
            _c.execute(text("""
                DELETE FROM staff_menu_registry WHERE menu_code = ANY(:codes)
            """), {"codes": list(_legacy_codes)})
        print("[DC_CONSOLIDATED_CLEANUP_048] ✅ Legacy consolidated menu rows cleaned up", flush=True)
    except Exception as _e:
        print(f"[DC_CONSOLIDATED_CLEANUP_048] ⚠️ {_e}", flush=True)

    # DC_CONSOLIDATED_001: Consolidated reports infrastructure
