    # ── DC_IGST_BACKFILL_001: Backfill is_igst flag + tax amounts from vendor.gst_type ──
    # One-time idempotent fix: for every purchase invoice whose vendor has gst_type='IGST',
    # set is_igst=True on the upload header, move cgst+sgst into igst on header AND line items.
    try:
        _mk_igst = 'igst_backfill_from_vendor_gst_type_001'
        _db_igst = SessionLocal()
        try:
            _already_igst = _mk_igst in _applied_keys
            if not _already_igst:
                # Step 1: Update upload header for ALL uploads where vendor has gst_type='IGST'
                _db_igst.execute(text("""
                    UPDATE purchase_invoice_uploads pu
                    SET    is_igst      = TRUE,
                           igst_amount  = COALESCE(pu.cgst_amount, 0)
                                        + COALESCE(pu.sgst_amount, 0)
                                        + COALESCE(pu.igst_amount, 0),
                           cgst_amount  = 0,
                           sgst_amount  = 0
                    FROM   vendor_master vm
                    WHERE  pu.vendor_id = vm.id
                      AND  vm.gst_type  = 'IGST'
                      AND  (pu.is_igst IS NULL OR pu.is_igst = FALSE)
                """))
                # Step 2: Update line items for all uploads linked to IGST vendors
                _db_igst.execute(text("""
                    UPDATE purchase_invoice_line_items pili
                    SET    igst_amount  = COALESCE(pili.cgst_amount, 0)
                                        + COALESCE(pili.sgst_amount, 0)
                                        + COALESCE(pili.igst_amount, 0),
                           igst_rate    = COALESCE(pili.cgst_rate, 0)
                                        + COALESCE(pili.sgst_rate, 0),
                           cgst_amount  = 0,
                           sgst_amount  = 0,
                           cgst_rate    = 0,
                           sgst_rate    = 0
                    FROM   purchase_invoice_uploads pu
                    JOIN   vendor_master vm ON pu.vendor_id = vm.id
                    WHERE  pili.upload_id = pu.id
                      AND  vm.gst_type    = 'IGST'
                """))
                _db_igst.execute(
                    text("INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT DO NOTHING"),
                    {"k": _mk_igst}
                )
                _db_igst.commit()
                print("[DC_IGST_BACKFILL_001] ✅ IGST backfill complete — is_igst set + tax flipped to IGST for all IGST-vendor invoices", flush=True)
            else:
                print("[DC_IGST_BACKFILL_001] ⏭️ already applied", flush=True)
        except Exception as _e_igst:
            print(f"[DC_IGST_BACKFILL_001] ⚠️ {_e_igst}", flush=True)
            try: _db_igst.rollback()
            except Exception: pass
        finally:
            _db_igst.close()
    except Exception as _e_igst2:
        print(f"[DC_IGST_BACKFILL_001] ⚠️ outer: {_e_igst2}", flush=True)

    # DC_TRAINING_VIDEOS_001: Training Videos System — tables, menu registration, initial sync
