    # ── DC-VNUM-001: Backfill all existing voucher_numbers to new co-prefix format ──
    # Old: PV2026050047  (no company prefix, monthly reset)
    # New: MRPV2026050047 (company prefix, FY-scoped sequence)
    # Mapping: co=2→ZY, co=3→MN, co=4→MR, co=5→MR
    # Renumbers each company+type group in ascending JV id order so the seq is
    # consistent with creation order.  reference_number on account_ledger and
    # party_ledger rows that stored the old voucher_number are also updated.
    # Idempotent: only processes rows whose voucher_number does NOT already start
    # with the correct company prefix.
    _vnum_key = 'dc_vnum_001_coprefix_backfill_20260528'
    try:
        from sqlalchemy import text as _vt
        from datetime import datetime as _vdt
        _vndb = SessionLocal()
        try:
            _vndb.execute(_vt("CREATE TABLE IF NOT EXISTS dc_migrations (key VARCHAR(120) PRIMARY KEY)"))
            _vndb.commit()
            _vndone = _vnum_key in _applied_keys
            if not _vndone:
                _co_map = {2: 'ZY', 3: 'MN', 4: 'MR', 5: 'MR'}
                _type_codes = {'JOURNAL': 'JV', 'CONTRA': 'CT', 'PAYMENT': 'PV', 'RECEIPT': 'RV'}
                _total_renamed = 0
                for _co_id, _co_pfx in _co_map.items():
                    for _vtype, _type_pfx in _type_codes.items():
                        _full_new_pfx = f'{_co_pfx}{_type_pfx}'
                        # Fetch all vouchers for this company+type that still use old format
                        _rows = _vndb.execute(_vt("""
                            SELECT id, voucher_number, voucher_date
                            FROM journal_vouchers
                            WHERE company_id=:co AND voucher_type=:vt
                              AND voucher_number NOT LIKE :pfx
                            ORDER BY id ASC
                        """), {'co': _co_id, 'vt': _vtype, 'pfx': f'{_full_new_pfx}%'}).fetchall()
                        if not _rows:
                            continue
                        # Determine starting seq: max existing new-format seq + 1
                        _last_new = _vndb.execute(_vt("""
                            SELECT voucher_number FROM journal_vouchers
                            WHERE company_id=:co AND voucher_type=:vt
                              AND voucher_number LIKE :pfx
                            ORDER BY id DESC LIMIT 1
                        """), {'co': _co_id, 'vt': _vtype, 'pfx': f'{_full_new_pfx}%'}).fetchone()
                        _seq = 1
                        if _last_new:
                            try:
                                _seq = int(_last_new[0][-4:]) + 1
                            except Exception:
                                _seq = 1
                        for _row in _rows:
                            _old_num = _row[1]
                            _ym = _row[2].strftime('%Y%m') if _row[2] else _vdt.now().strftime('%Y%m')
                            _new_num = f'{_full_new_pfx}{_ym}{_seq:04d}'
                            _seq += 1
                            # Update journal_vouchers
                            _vndb.execute(_vt(
                                "UPDATE journal_vouchers SET voucher_number=:nn WHERE id=:jid"
                            ), {'nn': _new_num, 'jid': _row[0]})
                            # Update account_ledger reference_number
                            _vndb.execute(_vt("""
                                UPDATE account_ledger
                                   SET reference_number=:nn
                                 WHERE reference_type='JOURNAL'
                                   AND reference_id=:jid
                                   AND reference_number=:on
                            """), {'nn': _new_num, 'jid': _row[0], 'on': _old_num})
                            # Update party_ledger reference_number
                            _vndb.execute(_vt("""
                                UPDATE party_ledger
                                   SET reference_number=:nn
                                 WHERE reference_type='JOURNAL'
                                   AND reference_id=:jid
                                   AND reference_number=:on
                            """), {'nn': _new_num, 'jid': _row[0], 'on': _old_num})
                            _total_renamed += 1
                _vndb.execute(_vt(
                    "INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT DO NOTHING"
                ), {'k': _vnum_key})
                _vndb.commit()
                print(
                    f"[DC-VNUM-001] ✅ Voucher number backfill complete: {_total_renamed} vouchers "
                    f"renamed to company-prefix format (ZY/MN/MR). "
                    f"New format: {{CO}}{{TYPE}}{{YYYYMM}}{{4-digit}}. FY-scoped sequence active.",
                    flush=True
                )
            else:
                print("[DC-VNUM-001] ⏭️  Already applied — skipping", flush=True)
        finally:
            _vndb.close()
    except Exception as _vn_e:
        print(f"[DC-VNUM-001] ⚠️ Migration (non-fatal): {_vn_e}", flush=True)

