    # DC-TXN-DEAL-SYNC-001 (Jun 2026): Backfill crm_lead_deals.deal_value_received and
    # crm_leads.deal_value_received from validated transactions.
    # Historical data had deal received = 0 and lead received out of sync because
    # validate_transaction never wrote back to the deal table.
    # Runs once (idempotent via dc_migrations); safe to re-run manually if needed.
    try:
        _heal_key = 'heal_deal_received_from_txn_20260606'
        _heal_db = SessionLocal()
        try:
            _heal_exists = _heal_key in _applied_keys
            if not _heal_exists:
                # Step 1: Update crm_lead_deals.deal_value_received per deal from validated txns
                _heal_db.execute(text("""
                    UPDATE crm_lead_deals d
                    SET deal_value_received = COALESCE(t.total_validated, 0),
                        deal_value_balance  = GREATEST(0, d.deal_value_total - COALESCE(t.total_validated, 0))
                    FROM (
                        SELECT deal_id, SUM(amount) AS total_validated
                        FROM crm_lead_transactions
                        WHERE validation_status = 'validated'
                          AND deal_id IS NOT NULL
                        GROUP BY deal_id
                    ) t
                    WHERE d.id = t.deal_id
                """))
                # Step 2: Update crm_leads.deal_value_received per lead from validated txns
                _heal_db.execute(text("""
                    UPDATE crm_leads l
                    SET deal_value_received = COALESCE(t.total_validated, 0),
                        deal_value_balance  = GREATEST(0, COALESCE(l.deal_value_total, 0) - COALESCE(t.total_validated, 0))
                    FROM (
                        SELECT lead_id, SUM(amount) AS total_validated
                        FROM crm_lead_transactions
                        WHERE validation_status = 'validated'
                          AND lead_id IS NOT NULL
                        GROUP BY lead_id
                    ) t
                    WHERE l.id = t.lead_id
                """))
                # Step 3: Zero out leads with no validated transactions (heal leads that only
                # had manual overrides but no actual validated payments)
                _heal_db.execute(text("""
                    UPDATE crm_leads l
                    SET deal_value_received = 0,
                        deal_value_balance  = GREATEST(0, COALESCE(l.deal_value_total, 0))
                    WHERE NOT EXISTS (
                        SELECT 1 FROM crm_lead_transactions t
                        WHERE t.lead_id = l.id AND t.validation_status = 'validated'
                    )
                    AND l.deal_value_received IS NOT NULL
                    AND l.deal_value_received > 0
                """))
                _heal_db.execute(
                    text("INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT DO NOTHING"),
                    {'k': _heal_key}
                )
                _heal_db.commit()
                print("[DC-TXN-DEAL-SYNC-001] ✅ deal_value_received backfill complete — deals & leads healed from validated txns", flush=True)
            else:
                print("[DC-TXN-DEAL-SYNC-001] ⏭️  Backfill already applied — skipping", flush=True)
        finally:
            _heal_db.close()
    except Exception as _heal_e:
        print(f"[DC-TXN-DEAL-SYNC-001] ⚠️ (non-fatal) {_heal_e}", flush=True)

