# DC Protocol: Host Header Sanitizer Middleware
# Fixes production errors caused by comma-delimited host headers (e.g., "myntreal.com, myntreal.in")
# Must run BEFORE TrustedHostMiddleware to sanitize the Host header
class HostHeaderSanitizerMiddleware:
    """
    ASGI Middleware to sanitize Host headers before TrustedHostMiddleware validation.
    
    Problem: Proxies sometimes forward comma-separated host aliases which fail exact matching.
    Solution: Extract only the first host and strip port numbers.
    
    DC Protocol: No data changes, only request preprocessing
    WVV Protocol: Validates host header format before authentication checks
    """
    def __init__(self, app):
        self.app = app
    
    async def __call__(self, scope, receive, send):
        if scope["type"] == "http":
            headers = list(scope.get("headers", []))
            new_headers = []
            for name, value in headers:
                if name.lower() == b"host":
                    # Decode, extract first host, strip port, re-encode
                    host_str = value.decode("latin-1")
                    # Handle comma-separated hosts (take first one)
                    if "," in host_str:
                        host_str = host_str.split(",")[0].strip()
                    # Strip port number if present
                    if ":" in host_str and not host_str.startswith("["):
                        host_str = host_str.split(":")[0]
                    value = host_str.encode("latin-1")
                new_headers.append((name, value))
            scope = dict(scope, headers=new_headers)
        await self.app(scope, receive, send)

# Trusted host middleware - Only for production
if not settings.DEBUG:
    # First add TrustedHostMiddleware
    app.add_middleware(
        TrustedHostMiddleware,
        allowed_hosts=settings.ALLOWED_HOSTS
    )
    # Then add HostHeaderSanitizerMiddleware (runs BEFORE TrustedHost in ASGI chain)
    app.add_middleware(HostHeaderSanitizerMiddleware)

# Add middleware to exclude Next.js routes from FastAPI
from fastapi import Request
from fastapi.responses import RedirectResponse

@app.middleware("http")
async def exclude_nextjs_routes(request: Request, call_next):
    """
    Expert Fix: Exclude Next.js routes from FastAPI processing
    Routes starting with /_next/ should be handled by Next.js server, not FastAPI
    """
    if request.url.path.startswith("/_next/"):
        # Return clean 404 for Next.js routes to force proper routing
        from fastapi.responses import JSONResponse
        return JSONResponse(
            status_code=404, 
            content={"detail": "Route handled by frontend server"}
        )
    
    response = await call_next(request)
    return response

