# Critical endpoints FIRST (before scaffolds to avoid conflicts)
@app.get("/health")
async def health_check():
    """
    Health check endpoint for deployment monitoring
    DC Protocol: Graceful degradation - returns 200 even if non-critical init fails
    WVV: Write (init), Verify (check status), Validate (return correct status code)
    
    CRITICAL FIX (Dec 12, 2025): Health check must return 200 for deployment to proceed.
    Initialization failures are logged but don't block the health check.
    This prevents the "port was never opened" production error.
    """
    from fastapi.responses import JSONResponse
    from app.core.lazy_initialization import ensure_initialized
    
    # DC Protocol: Trigger lazy initialization on first request
    # GRACEFUL DEGRADATION: Log errors but don't block health check
    init_status = "ok"
    init_error = None
    try:
        ensure_initialized()
    except Exception as e:
        logging.error(f"[HEALTH] ⚠️ Initialization warning (non-blocking): {e}")
        init_status = "degraded"
        init_error = str(e)
        # DC PROTOCOL: Do NOT return 503 - this blocks deployment
        # The system can still serve requests even if some init steps failed
    
    # DC Protocol: Check database connectivity (critical)
    db_status = "unknown"
    try:
        from app.core.database import SessionLocal
        db = SessionLocal()
        try:
            from sqlalchemy import text
            db.execute(text("SELECT 1"))
            db_status = "connected"
        finally:
            db.close()
    except Exception as e:
        logging.error(f"[HEALTH] ❌ Database check failed: {e}")
        db_status = f"error: {str(e)}"
        # Only return 503 if database is completely unreachable
        return JSONResponse(
            status_code=503,
            content={
                "status": "unhealthy",
                "service": "MNR EV Reference Program API",
                "version": "2.0.0",
                "initialization": init_status,
                "database": db_status,
                "error": "Database connection failed",
                "message": "Cannot connect to database - check DATABASE_URL"
            }
        )
    
    from app.core.redis import get_redis_client
    
    redis_status = "disconnected"
    try:
        redis_client = get_redis_client()
        if redis_client:
            await redis_client.ping()
            redis_status = "connected"
    except Exception as e:
        redis_status = f"error: {str(e)}"
    
    schema_status = "ok"
    missing_columns = []
    try:
        from app.core.database import SessionLocal
        from sqlalchemy import text
        db = SessionLocal()
        try:
            critical_columns = [
                ("crm_leads", "deal_value_total"),
                ("crm_leads", "deal_value_received"),
                ("crm_leads", "deal_value_balance"),
            ]
            for table_name, column_name in critical_columns:
                result = db.execute(text(
                    f"SELECT column_name FROM information_schema.columns "
                    f"WHERE table_name='{table_name}' AND column_name='{column_name}'"
                ))
                if result.fetchone() is None:
                    missing_columns.append(f"{table_name}.{column_name}")
            if missing_columns:
                schema_status = "missing_columns"
                logging.warning(f"[HEALTH] ⚠️ Schema drift detected - missing: {missing_columns}")
        finally:
            db.close()
    except Exception as e:
        schema_status = f"check_failed: {str(e)[:50]}"
        logging.error(f"[HEALTH] ❌ Schema validation failed: {e}")
    
    overall_status = "healthy"
    if init_status == "degraded" or schema_status != "ok":
        overall_status = "degraded"
    
    return {
        "status": overall_status,
        "service": "MNR EV Reference Program API",
        "version": "2.0.0",
        "initialization": init_status,
        "init_warning": init_error,
        "database": db_status,
        "redis_cache": redis_status,
        "schema": schema_status,
        "missing_columns": missing_columns if missing_columns else None
    }

