# DC-CRM-DATE-BACKFILL-001 (Jun 2026): Backfill missing primary date fields for WON leads
# across ALL segments — fixing Executive Dashboard vs Category Lead Master discrepancy.
#
# ROOT CAUSE: Solar leads moved to Won without recording submit_date (bank application date).
# The dashboard WON bucket date logic: if solar_pipeline_status IS NOT NULL → submit_date;
# else → actual_close_date. When submit_date IS NULL the COALESCE falls through to
# actual_close_date/created_at, causing the lead to bucket into a DIFFERENT month than
# what Category Lead Master shows under its submit_date filter.
#
# Fix A — SOLAR (21 leads): SET submit_date = actual_close_date
#   Condition: submit_date IS NULL AND solar_pipeline_status IS NOT NULL (and not excluded stage)
#   Rationale: actual_close_date = date deal was won ≈ bank application date; always ≤
#              solar_pipeline_status_updated_at (which reflects the CURRENT stage, not
#              the original submission — e.g. electricity_bill_change updated_at is weeks later).
#
# Fix B — NON-SOLAR (2 leads: #6 EV B2B, #3899 EV B2C): SET actual_close_date = updated_at
#   Condition: id IN (6, 3899) AND actual_close_date IS NULL
#   Rationale: updated_at = when the lead was last touched/marked won — best available proxy.
#
# Idempotent: each UPDATE only targets rows where target field IS NULL.
# Key: dc_crm_date_backfill_20260624
_cdb_db = SessionLocal()
try:
    from sqlalchemy import text as _cdb_text
    _cdb_mk = "dc_crm_date_backfill_20260624"
    if _cdb_mk not in _applied_keys:
        # Fix A: Solar leads — backfill submit_date from actual_close_date
        _cdb_solar = _cdb_db.execute(_cdb_text("""
            UPDATE crm_leads
               SET submit_date = CAST(actual_close_date AS DATE),
                   updated_at  = NOW()
             WHERE submit_date IS NULL
               AND solar_pipeline_status IS NOT NULL
               AND solar_pipeline_status NOT IN
                   ('loan_rejected','documents_issue','not_interested','cancelled','different_vendor')
               AND status IN ('won','order_placed','dispatched','delivered','installed','completed')
               AND actual_close_date IS NOT NULL
        """))
        # Fix B: Non-solar leads with missing actual_close_date — backfill from updated_at
        _cdb_nonsolar = _cdb_db.execute(_cdb_text("""
            UPDATE crm_leads
               SET actual_close_date = CAST(updated_at AS DATE),
                   updated_at        = NOW()
             WHERE id IN (6, 3899)
               AND actual_close_date IS NULL
               AND status IN ('won','order_placed','dispatched','delivered','installed','completed')
        """))
        _cdb_db.execute(_cdb_text(
            "INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT (key) DO NOTHING"
        ), {"k": _cdb_mk})
        _cdb_db.commit()
        print(
            f"[DC-CRM-DATE-BACKFILL-001] ✅ Backfilled {_cdb_solar.rowcount} solar submit_date(s) + "
            f"{_cdb_nonsolar.rowcount} non-solar actual_close_date(s)",
            flush=True
        )
    else:
        print("[DC-CRM-DATE-BACKFILL-001] ✅ Already applied — skip", flush=True)
except Exception as _cdb_e:
    print(f"[DC-CRM-DATE-BACKFILL-001] ⚠️ Backfill error (non-fatal): {_cdb_e}", flush=True)
    try:
        _cdb_db.rollback()
    except Exception:
        pass
finally:
    try:
        _cdb_db.close()
    except Exception:
        pass

# DC-PL-JV-PARTY-REPAIR-001 (Jun 2026): Fix party_ledger entries mis-attributed to the wrong
# party due to the DC-PARTY-LOCK-STALE-002 stale-ID race condition (now fixed in JV creation).
#
# Symptom: a PAYMENT or RECEIPT voucher for "Marshalls Pet Zone" appears in "E-Ashwa
# Automotive" party ledger because the stale party_id from a previous dropdown selection
# was used when posting the party_ledger entry — even though jv.party_name was correct.
#
# Fix: for every JOURNAL-referenced PAYMENT/RECEIPT/CONTRA entry in party_ledger where
# UPPER(pl.party_name) != UPPER(jv.party_name), overwrite pl.party_name + pl.party_id
# with the correct values from journal_vouchers. Then recompute running_balance for all
# affected party groups (both wrongly-assigned and correctly-assigned parties).
#
# Idempotent: WHERE condition only matches mismatches → zero rows on re-run.
# Key: dc_pl_jv_party_repair_20260624
_plr_db = SessionLocal()
try:
    from sqlalchemy import text as _plr_text
    _plr_mk = "dc_pl_jv_party_repair_20260624"
    if _plr_mk not in _applied_keys:
        # Step 1: Identify all mis-attributed entries to know which party groups need rebalancing
        _plr_mismatch = _plr_db.execute(_plr_text("""
            SELECT pl.id           AS pl_id,
                   pl.company_id,
                   COALESCE(pl.party_id, 0)               AS old_party_id,
                   UPPER(TRIM(COALESCE(pl.party_name,''))) AS old_party_name,
                   UPPER(TRIM(jv.party_name))              AS new_party_name,
                   COALESCE(jv.party_id, 0)               AS new_party_id
            FROM party_ledger pl
            JOIN journal_vouchers jv ON jv.id = pl.reference_id
            WHERE pl.reference_type = 'JOURNAL'
              AND pl.voucher_type IN ('PAYMENT', 'RECEIPT', 'CONTRA')
              AND jv.party_name IS NOT NULL
              AND TRIM(jv.party_name) != ''
              AND pl.party_name IS NOT NULL
              AND UPPER(TRIM(pl.party_name)) <> UPPER(TRIM(jv.party_name))
              AND jv.status != 'CANCELLED'
        """)).fetchall()

        # Step 2: Fix party_name + party_id in one UPDATE
        _plr_result = _plr_db.execute(_plr_text("""
            UPDATE party_ledger pl
               SET party_name = UPPER(TRIM(jv.party_name)),
                   party_id   = COALESCE(jv.party_id, 0),
                   updated_at = NOW()
            FROM journal_vouchers jv
            WHERE pl.reference_type = 'JOURNAL'
              AND pl.reference_id   = jv.id
              AND pl.voucher_type IN ('PAYMENT', 'RECEIPT', 'CONTRA')
              AND jv.party_name IS NOT NULL
              AND TRIM(jv.party_name) != ''
              AND pl.party_name IS NOT NULL
              AND UPPER(TRIM(pl.party_name)) <> UPPER(TRIM(jv.party_name))
              AND jv.status != 'CANCELLED'
        """))
        _plr_fixed = _plr_result.rowcount

        # Step 3: Recompute running_balance for every affected party group.
        # Both the WRONG party (now has fewer entries) and CORRECT party (now has more entries)
        # need to be rebalanced. Formula: SUM(debit - credit) over (date, id) order — positive = Dr.
        _affected_groups = set()
        for _row in _plr_mismatch:
            _affected_groups.add((_row.company_id, _row.old_party_id, _row.old_party_name))
            _affected_groups.add((_row.company_id, _row.new_party_id, _row.new_party_name))

        _plr_rb_fixed = 0
        for (_cid, _pid, _pnm) in _affected_groups:
            try:
                _rb_res = _plr_db.execute(_plr_text("""
                    UPDATE party_ledger pl
                       SET running_balance = sub.rb
                    FROM (
                        SELECT id,
                               SUM(COALESCE(debit_amount,0) - COALESCE(credit_amount,0))
                                   OVER (ORDER BY transaction_date, id
                                         ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS rb
                        FROM party_ledger
                        WHERE company_id = :cid
                          AND COALESCE(party_id, 0) = :pid
                          AND UPPER(TRIM(COALESCE(party_name,''))) = :pnm
                    ) sub
                    WHERE pl.id = sub.id
                      AND pl.running_balance IS DISTINCT FROM sub.rb
                """), {"cid": _cid, "pid": _pid, "pnm": _pnm})
                _plr_rb_fixed += _rb_res.rowcount
            except Exception:
                pass  # non-fatal: DC-PL-BAL-CLIENT-001 (client-side recompute) corrects display

        _plr_db.execute(_plr_text(
            "INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT (key) DO NOTHING"
        ), {"k": _plr_mk})
        _plr_db.commit()
        print(
            f"[DC-PL-JV-PARTY-REPAIR-001] ✅ Fixed {_plr_fixed} mis-attributed party_ledger "
            f"entry/entries; rebalanced {_plr_rb_fixed} running_balance row(s)",
            flush=True
        )
    else:
        print("[DC-PL-JV-PARTY-REPAIR-001] ✅ Already applied — skip", flush=True)
except Exception as _plr_e:
    print(f"[DC-PL-JV-PARTY-REPAIR-001] ⚠️ Repair error (non-fatal): {_plr_e}", flush=True)
    try:
        _plr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _plr_db.close()
    except Exception:
        pass

