# DC-SUBMIT-DATE-REPAIR-001 (Jul 2026): Fix out-of-range submit_date / complete_date values.
# Root cause: lead #7730 had submit_date='62026-02-09' (data-entry typo — extra leading digit).
# When SQLAlchemy fetches this row psycopg2 calls datetime.date(62026,2,9) → ValueError:
# "year 62026 is out of range", crashing master-leads / leads / lead-analytics for every
# request that includes this lead in the result set.
# Fix A: MAKE_DATE using (year % 10000) to recover the intended 4-digit year for any row
#         where EXTRACT(YEAR) > 2099 in submit_date or complete_date.
# Fix B: DB CHECK constraints on both columns so future bad writes are rejected at DB level.
# Idempotent: WHERE condition only matches rows with year > 2099, none on re-run.
# Key: dc_submit_date_repair_20260708
_sdr_db = SessionLocal()
try:
    from sqlalchemy import text as _sdr_text
    _sdr_mk = "dc_submit_date_repair_20260708"
    if _sdr_mk not in _applied_keys:
        # Fix A: repair out-of-range submit_date (e.g. 62026 → 2026)
        _sdr_sub = _sdr_db.execute(_sdr_text("""
            UPDATE crm_leads
               SET submit_date = MAKE_DATE(
                       (EXTRACT(YEAR FROM submit_date)::BIGINT % 10000)::INT,
                       EXTRACT(MONTH FROM submit_date)::INT,
                       EXTRACT(DAY FROM submit_date)::INT
                   )
             WHERE submit_date IS NOT NULL
               AND EXTRACT(YEAR FROM submit_date) > 2099
        """))
        # Fix A: repair out-of-range complete_date
        _sdr_comp = _sdr_db.execute(_sdr_text("""
            UPDATE crm_leads
               SET complete_date = MAKE_DATE(
                       (EXTRACT(YEAR FROM complete_date)::BIGINT % 10000)::INT,
                       EXTRACT(MONTH FROM complete_date)::INT,
                       EXTRACT(DAY FROM complete_date)::INT
                   )
             WHERE complete_date IS NOT NULL
               AND EXTRACT(YEAR FROM complete_date) > 2099
        """))
        # Fix B: CHECK constraints — reject future out-of-range writes at DB level
        try:
            _sdr_db.execute(_sdr_text(
                "ALTER TABLE crm_leads "
                "ADD CONSTRAINT chk_submit_date_year "
                "CHECK (submit_date IS NULL OR (EXTRACT(YEAR FROM submit_date) BETWEEN 2000 AND 2099))"
            ))
        except Exception:
            _sdr_db.rollback()
        try:
            _sdr_db.execute(_sdr_text(
                "ALTER TABLE crm_leads "
                "ADD CONSTRAINT chk_complete_date_year "
                "CHECK (complete_date IS NULL OR (EXTRACT(YEAR FROM complete_date) BETWEEN 2000 AND 2099))"
            ))
        except Exception:
            _sdr_db.rollback()
        _sdr_db.execute(_sdr_text(
            "INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT (key) DO NOTHING"
        ), {"k": _sdr_mk})
        _sdr_db.commit()
        print(
            f"[DC-SUBMIT-DATE-REPAIR-001] ✅ Fixed {_sdr_sub.rowcount} submit_date(s) + "
            f"{_sdr_comp.rowcount} complete_date(s); CHECK constraints added",
            flush=True
        )
    else:
        print("[DC-SUBMIT-DATE-REPAIR-001] ✅ Already applied — skip", flush=True)
except Exception as _sdr_e:
    print(f"[DC-SUBMIT-DATE-REPAIR-001] ⚠️ Non-fatal: {_sdr_e}", flush=True)
    try:
        _sdr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _sdr_db.close()
    except Exception:
        pass

# ── DC-CANCEL-REGEN-001 (Jun 2026): Partial unique index on vgk_cash_income_entries ──────────
# Problem: the original UNIQUE (company_id, partner_id, source_lead_id, level) constraint
# applies to ALL rows including CANCELLED ones.  Cancelling a wrong entry then retriggering
# fails with a unique-constraint violation (or the Python idempotency check silently skips it).
# Fix: replace the full unique constraint with a partial unique index that excludes CANCELLED,
# so cancelled entries become historical-only and do not block regeneration at the same slot.
try:
    from sqlalchemy import text as _cr_text
    _cr_mk  = "vgk_cash_income_partial_unique_20260627"
    _cr_db  = SessionLocal()
    if _cr_mk not in _applied_keys:
        # Drop old full unique constraint
        _cr_db.execute(_cr_text(
            "ALTER TABLE vgk_cash_income_entries DROP CONSTRAINT IF EXISTS uq_vgk_cash_income_lead_partner_level"
        ))
        # Create partial unique index — only enforces uniqueness for non-cancelled entries
        _cr_db.execute(_cr_text("""
            CREATE UNIQUE INDEX IF NOT EXISTS uq_vgk_cash_income_lead_partner_level
            ON vgk_cash_income_entries(company_id, partner_id, source_lead_id, level)
            WHERE status != 'CANCELLED'
        """))
        _cr_db.execute(_cr_text(
            "INSERT INTO dc_migrations (key) VALUES (:k) ON CONFLICT (key) DO NOTHING"
        ), {"k": _cr_mk})
        _cr_db.commit()
        print("[DC-CANCEL-REGEN-001] ✅ Partial unique index on vgk_cash_income_entries applied", flush=True)
    else:
        print("[DC-CANCEL-REGEN-001] ✅ Already applied — skip", flush=True)
except Exception as _cr_e:
    print(f"[DC-CANCEL-REGEN-001] ⚠️ Non-fatal: {_cr_e}", flush=True)
    try:
        _cr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _cr_db.close()
    except Exception:
        pass

