# ── DC-AL-CHAIN-REPAIR-001: Recompute running_balance for BANK/CASH/UPI accounts ──
# One-time data repair: corrects running_balance chains corrupted by concurrent inserts
# or backdated/out-of-order entries.  Pure-SQL window function — no per-row Python loop,
# no account_id (doesn't exist; composite key is company_id+account_type+account_name),
# uniform dr-cr sign for all types (matches _fmtBal / Part 2 convention).
try:
    from sqlalchemy import text as _alr_text
    from app.core.database import SessionLocal as _alr_SL
    _alr_db = _alr_SL()
    _alr_mk = "dc_al_bank_chain_repair_20260628"
    _alr_exists = _alr_mk in _applied_keys
    if not _alr_exists:
        # Single UPDATE using a SQL window function — runs entirely in PostgreSQL.
        # PARTITION BY (company_id, account_type, account_name) = one chain per account.
        # ORDER BY (transaction_date ASC, id ASC) = strict chronological order.
        # SUM(dr - cr) OVER (... ROWS UNBOUNDED PRECEDING) = cumulative running balance.
        _alr_db.execute(_alr_text("""
            UPDATE account_ledger al
            SET    running_balance = calc.new_bal
            FROM (
                SELECT
                    id,
                    SUM(COALESCE(debit_amount, 0) - COALESCE(credit_amount, 0))
                        OVER (
                            PARTITION BY company_id, account_type, account_name
                            ORDER BY transaction_date ASC, id ASC
                            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
                        ) AS new_bal
                FROM account_ledger
                WHERE account_type IN ('BANK', 'CASH', 'UPI')
            ) calc
            WHERE al.id = calc.id
        """))
        _alr_db.execute(
            _alr_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
            {"k": _alr_mk}
        )
        _alr_db.commit()
        print("[DC-AL-CHAIN-REPAIR-001] ✅ BANK/CASH/UPI running_balance chains repaired", flush=True)
    else:
        print("[DC-AL-CHAIN-REPAIR-001] ✅ Already applied — skip", flush=True)
except Exception as _alr_e:
    print(f"[DC-AL-CHAIN-REPAIR-001] ⚠️ Non-fatal: {_alr_e}", flush=True)
    try:
        _alr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _alr_db.close()
    except Exception:
        pass

# ── DC-AL-SIGN-REPAIR-001: Backfill running_balance using dual sign convention ──
# Supersedes DC-AL-CHAIN-REPAIR-001 (BANK/CASH/UPI uniform dr-cr).
# Now covers ALL account types:
#   DEBIT-NORMAL  {BANK, CASH, UPI, EXPENSE, ASSET} → cumulative SUM(dr - cr)
#   CREDIT-NORMAL {everything else}                  → cumulative SUM(cr - dr)
# Runs once (dc_migrations guard). Pure PostgreSQL window function — no Python loop.
try:
    from sqlalchemy import text as _asr_text
    from app.core.database import SessionLocal as _asr_SL
    _asr_db = _asr_SL()
    _asr_mk = "dc_al_sign_repair_20260629"
    _asr_exists = _asr_mk in _applied_keys
    if not _asr_exists:
        _asr_db.execute(_asr_text("""
            UPDATE account_ledger al
            SET    running_balance = calc.new_bal
            FROM (
                SELECT id,
                    CASE
                        WHEN account_type IN ('BANK', 'CASH', 'UPI', 'EXPENSE', 'ASSET') THEN
                            SUM(COALESCE(debit_amount, 0) - COALESCE(credit_amount, 0))
                                OVER (
                                    PARTITION BY company_id, account_type, account_name
                                    ORDER BY transaction_date ASC, id ASC
                                    ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
                                )
                        ELSE
                            SUM(COALESCE(credit_amount, 0) - COALESCE(debit_amount, 0))
                                OVER (
                                    PARTITION BY company_id, account_type, account_name
                                    ORDER BY transaction_date ASC, id ASC
                                    ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
                                )
                    END AS new_bal
                FROM account_ledger
            ) calc
            WHERE al.id = calc.id
        """))
        _asr_db.execute(
            _asr_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
            {"k": _asr_mk}
        )
        _asr_db.commit()
        print("[DC-AL-SIGN-REPAIR-001] ✅ All account_ledger running_balance chains repaired (dual sign)", flush=True)
    else:
        print("[DC-AL-SIGN-REPAIR-001] ✅ Already applied — skip", flush=True)
except Exception as _asr_e:
    print(f"[DC-AL-SIGN-REPAIR-001] ⚠️ Non-fatal: {_asr_e}", flush=True)
    try:
        _asr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _asr_db.close()
    except Exception:
        pass

