# ─── DC-SLAB-L1-ONLY-CLEANUP-001 ────────────────────────────────────────────
# Solar Bonanza (₹3,000 SLAB_BONUS) must go ONLY to the L1 ground-source partner.
# Bug: release_advance() for CIBIL path had no level guard, so every L2 advance
# release also triggered apply_slab_bonus_if_active → wrong SLAB_BONUS entries.
# This migration: (a) cancels all 8 wrong entries, (b) reverses wallet for any
# partner where SLAB_BONUS_PAYOUT did not already zero their balance.
# Code fix: vgk_solar_advance.py line ~848 — `if _level == 1` guard added.
# ─────────────────────────────────────────────────────────────────────────────
try:
    from sqlalchemy import text as _slc_text
    _slc_db = SessionLocal()
    try:
        _slc_mk = "dc_slab_l1_only_cleanup_20260707"
        _slc_done = _slc_mk in _applied_keys
        if not _slc_done:
            from datetime import datetime as _slc_dt
            _slc_now = _slc_dt.now()

            # Step 1: Find every SLAB_BONUS entry where the receiving partner
            # is NOT the lead's L1 (associated_partner_id).
            _slc_wrong = _slc_db.execute(_slc_text("""
                SELECT e.id, e.entry_number, e.partner_id,
                       e.commission_amount, e.net_payout, e.company_id
                FROM vgk_cash_income_entries e
                JOIN crm_leads l ON l.id = e.source_lead_id
                WHERE e.kind    = 'SLAB_BONUS'
                  AND e.level   = 0
                  AND e.status != 'CANCELLED'
                  AND e.partner_id != l.associated_partner_id
            """)).fetchall()

            _slc_cancelled = 0
            _slc_reversed  = []

            for _se in _slc_wrong:
                # Step 2: Cancel the wrong VCI entry
                _slc_db.execute(_slc_text("""
                    UPDATE vgk_cash_income_entries
                       SET status           = 'CANCELLED',
                           cancelled_reason = 'DC-SLAB-L1-ONLY-CLEANUP-001: Solar Bonanza wrongly issued to L2/senior partner. Only L1 ground-source is eligible.',
                           updated_at       = :now
                     WHERE id = :eid AND status != 'CANCELLED'
                """), {"eid": _se.id, "now": _slc_now})
                _slc_cancelled += 1

                # Step 3: Check whether SLAB_BONUS_PAYOUT already zeroed
                # this partner's wallet (happens automatically for most partners
                # during the advance release cycle). If not, the wrong credit
                # is still sitting in the wallet and must be reversed.
                _slc_payout = _slc_db.execute(_slc_text("""
                    SELECT 1 FROM vgk_wallet_transactions
                     WHERE partner_id = :pid
                       AND txn_type   = 'SLAB_BONUS_PAYOUT'
                     LIMIT 1
                """), {"pid": _se.partner_id}).fetchone()

                if not _slc_payout:
                    # No PAYOUT → net credit still in wallet. Reverse net_payout.
                    _slc_p = _slc_db.execute(_slc_text(
                        "SELECT vgk_cash_wallet FROM official_partners "
                        "WHERE id = :pid FOR UPDATE"
                    ), {"pid": _se.partner_id}).fetchone()
                    _slc_wb  = float(_slc_p.vgk_cash_wallet or 0) if _slc_p else 0.0
                    _slc_net = float(_se.net_payout or 0)
                    _slc_wa  = _slc_wb - _slc_net

                    _slc_db.execute(_slc_text("""
                        UPDATE official_partners
                           SET vgk_cash_wallet = :wa, updated_at = :now
                         WHERE id = :pid
                    """), {"wa": _slc_wa, "pid": _se.partner_id, "now": _slc_now})

                    _slc_db.execute(_slc_text("""
                        INSERT INTO vgk_wallet_transactions
                               (company_id, partner_id, txn_type, direction,
                                amount, wallet_before, wallet_after,
                                ref_type, ref_id, description, created_at)
                        VALUES (:cid, :pid, 'INCOME_DEDUCTION', 'DR',
                                :amt, :wb, :wa,
                                'VGK_VCI_CANCEL', :rid,
                                'DC-SLAB-L1-ONLY-CLEANUP-001: Reversal — wrong Solar Bonanza issued to non-L1 partner (' || :en || ')',
                                :now)
                    """), {
                        "cid": _se.company_id, "pid": _se.partner_id,
                        "amt": _slc_net, "wb": _slc_wb, "wa": _slc_wa,
                        "rid": _se.id, "en": _se.entry_number,
                        "now": _slc_now,
                    })
                    _slc_reversed.append((_se.partner_id, _se.entry_number, _slc_net))

            _slc_db.execute(_slc_text(
                "INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"
            ), {"k": _slc_mk})
            _slc_db.commit()
            print(
                f"[DC-SLAB-L1-ONLY-CLEANUP-001] ✅ Cancelled {_slc_cancelled} wrong "
                f"SLAB_BONUS entries. Wallet reversals: {_slc_reversed}",
                flush=True,
            )
        else:
            print("[DC-SLAB-L1-ONLY-CLEANUP-001] ⏭️ Already applied — skipping", flush=True)
    except Exception as _slc_e:
        print(f"[DC-SLAB-L1-ONLY-CLEANUP-001] ⚠️ Non-fatal: {_slc_e}", flush=True)
        try: _slc_db.rollback()
        except Exception: pass
    finally:
        try: _slc_db.close()
        except Exception: pass
except Exception as _slc_outer:
    print(f"[DC-SLAB-L1-ONLY-CLEANUP-001] ⚠️ Outer error: {_slc_outer}", flush=True)

