# DC-PREMATURE-SOLAR-DRAFT-001 (Jul 2026): Cancel all COMMISSION DRAFTs created before the
# solar pipeline reached 'completed' status, and reverse the wallet credits that were posted
# at DRAFT creation (DC-VGK-FLOW-001).  Affects leads with a non-null, non-empty
# solar_pipeline_status that is not 'completed' — covers both category_id=6 and others
# (e.g. category_id=19) that were previously unprotected by DC-SOLAR-STAGE-GATE-001.
# Fixed by DC-SOLAR-GATE-ALLCAT-001 in generate_vgk_cash_income_drafts.
try:
    _psd_key = 'dc_cancel_premature_solar_drafts_20260711'
    _psd_db  = SessionLocal()
    from sqlalchemy import text as _txP
    from decimal import Decimal as _DP
    from datetime import datetime as _dtP
    try:
        _psd_applied = _psd_key in _applied_keys
        if not _psd_applied:
            _nowP = _dtP.now()
            _psd_rows = _psd_db.execute(_txP("""
                SELECT vci.id, vci.partner_id, vci.commission_amount,
                       vci.source_lead_id, vci.company_id, vci.entry_number
                FROM vgk_cash_income_entries vci
                JOIN crm_leads l ON l.id = vci.source_lead_id
                WHERE vci.kind   = 'COMMISSION'
                  AND vci.status = 'DRAFT'
                  AND l.solar_pipeline_status IS NOT NULL
                  AND l.solar_pipeline_status != ''
                  AND l.solar_pipeline_status != 'completed'
                ORDER BY vci.partner_id, vci.id
                FOR UPDATE OF vci
            """)).fetchall()

            _psd_cancelled = 0
            _psd_wallet_reversed = 0
            for _pr in _psd_rows:
                # Use SAVEPOINT per entry so a single failure doesn't abort the whole txn
                _psd_db.execute(_txP("SAVEPOINT sp_psd_entry"))
                try:
                    _comm = _DP(str(_pr.commission_amount or 0))
                    # 1. Cancel the DRAFT entry
                    _psd_db.execute(_txP("""
                        UPDATE vgk_cash_income_entries
                        SET status           = 'CANCELLED',
                            cancelled_reason = 'DC-PREMATURE-SOLAR-DRAFT-001: Solar pipeline not yet completed — wallet credit reversed',
                            updated_at       = :now
                        WHERE id = :vid
                    """), {'vid': _pr.id, 'now': _nowP})
                    _psd_cancelled += 1

                    # 2. Reverse wallet credit: debit partner wallet by commission_amount
                    if _comm > 0:
                        _wallet_row = _psd_db.execute(_txP("""
                            SELECT id, vgk_cash_wallet FROM official_partners
                            WHERE id = :pid FOR UPDATE
                        """), {'pid': _pr.partner_id}).fetchone()
                        if _wallet_row:
                            _wb = _DP(str(_wallet_row.vgk_cash_wallet or 0))
                            _wa = max(_DP('0'), _wb - _comm)
                            _psd_db.execute(_txP("""
                                UPDATE official_partners
                                SET vgk_cash_wallet = :wa, updated_at = :now
                                WHERE id = :pid
                            """), {'wa': float(_wa), 'pid': _pr.partner_id, 'now': _nowP})
                            # 3. Log wallet deduction transaction (INCOME_DEDUCTION = income credit reversal)
                            _psd_db.execute(_txP("""
                                INSERT INTO vgk_wallet_transactions
                                    (company_id, partner_id, txn_type, direction,
                                     amount, wallet_before, wallet_after,
                                     ref_type, ref_id, description, created_at)
                                VALUES
                                    (:co, :pid, 'INCOME_DEDUCTION', 'DR',
                                     :amt, :wb, :wa,
                                     'VGK_CASH_INCOME', :rid,
                                     :desc, :now)
                            """), {
                                'co':  _pr.company_id,
                                'pid': _pr.partner_id,
                                'amt': float(_comm),
                                'wb':  float(_wb),
                                'wa':  float(_wa),
                                'rid': _pr.id,
                                'desc': (
                                    f'Wallet reversal — premature COMMISSION DRAFT cancelled '
                                    f'({_pr.entry_number}) lead#{_pr.source_lead_id} '
                                    f'| DC-PREMATURE-SOLAR-DRAFT-001'
                                ),
                                'now': _nowP,
                            })
                            _psd_wallet_reversed += 1
                    _psd_db.execute(_txP("RELEASE SAVEPOINT sp_psd_entry"))
                    print(
                        f"[DC-PREMATURE-SOLAR-DRAFT] cancelled {_pr.entry_number} "
                        f"lead#{_pr.source_lead_id} pid={_pr.partner_id} "
                        f"comm={float(_comm)}", flush=True
                    )
                except Exception as _pr_e:
                    _psd_db.execute(_txP("ROLLBACK TO SAVEPOINT sp_psd_entry"))
                    print(f"[DC-PREMATURE-SOLAR-DRAFT] ⚠️ entry {_pr.id}: {_pr_e}", flush=True)

            _psd_db.execute(
                _txP("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _psd_key}
            )
            _psd_db.commit()
            print(
                f"[DC-PREMATURE-SOLAR-DRAFT] ✅ Complete: {_psd_cancelled} DRAFTs cancelled, "
                f"{_psd_wallet_reversed} wallet reversals posted", flush=True
            )
        else:
            print("[DC-PREMATURE-SOLAR-DRAFT] ⏭️ Already applied — skipping", flush=True)
    except Exception as _psd_e:
        print(f"[DC-PREMATURE-SOLAR-DRAFT] ⚠️ {_psd_e}", flush=True)
        try: _psd_db.rollback()
        except Exception: pass
    finally:
        try: _psd_db.close()
        except Exception: pass
except Exception as _psd_outer:
    print(f"[DC-PREMATURE-SOLAR-DRAFT] ⚠️ outer: {_psd_outer}", flush=True)

# DC-EXTRA-COMM-001 (Jul 2026): Special Bonanza Extra Commission schema migration.
# Adds: bonanza columns (trigger_event, ec_l1–l5_amount), bonanza_category_filters table,
# bonanza_extra_commission_log table, expands kind/txn_type CHECK constraints.
try:
    from sqlalchemy import text as _ec_text
    _ec_mk  = 'dc_extra_commission_bonanza_001'
    _ec_db  = SessionLocal()
    try:
        _ec_applied = _ec_mk in _applied_keys
        if not _ec_applied:
            # 1 — New columns on bonanza
            _ec_db.execute(_ec_text("""
                ALTER TABLE bonanza
                    ADD COLUMN IF NOT EXISTS trigger_event   VARCHAR(20),
                    ADD COLUMN IF NOT EXISTS ec_l1_amount    NUMERIC(12,2),
                    ADD COLUMN IF NOT EXISTS ec_l2_amount    NUMERIC(12,2),
                    ADD COLUMN IF NOT EXISTS ec_l3_amount    NUMERIC(12,2),
                    ADD COLUMN IF NOT EXISTS ec_l4_amount    NUMERIC(12,2),
                    ADD COLUMN IF NOT EXISTS ec_l5_amount    NUMERIC(12,2)
            """))

            # 2 — Expand bonanza reward_type CHECK to include 'extra_commission'
            _ec_db.execute(_ec_text("""
                ALTER TABLE bonanza
                    DROP CONSTRAINT IF EXISTS bonanza_reward_type_check
            """))
            _ec_db.execute(_ec_text("""
                ALTER TABLE bonanza
                    ADD CONSTRAINT bonanza_reward_type_check
                    CHECK (reward_type IN (
                        'cash','bonus','award','gift','slab_wise','extra_commission'
                    ))
            """))

            # 3 — trigger_event CHECK constraint
            _ec_db.execute(_ec_text("""
                ALTER TABLE bonanza
                    DROP CONSTRAINT IF EXISTS bonanza_trigger_event_check
            """))
            _ec_db.execute(_ec_text("""
                ALTER TABLE bonanza
                    ADD CONSTRAINT bonanza_trigger_event_check
                    CHECK (trigger_event IS NULL OR trigger_event IN (
                        'file_submitted','first_payment','file_completed'
                    ))
            """))

            # 4 — bonanza_category_filters table
            _ec_db.execute(_ec_text("""
                CREATE TABLE IF NOT EXISTS bonanza_category_filters (
                    id          SERIAL PRIMARY KEY,
                    bonanza_id  INTEGER NOT NULL REFERENCES bonanza(id) ON DELETE CASCADE,
                    category_id INTEGER NOT NULL REFERENCES signup_categories(id) ON DELETE CASCADE,
                    CONSTRAINT uq_bonanza_cat_filter UNIQUE (bonanza_id, category_id)
                )
            """))
            _ec_db.execute(_ec_text("""
                CREATE INDEX IF NOT EXISTS idx_bonanza_cat_filter_bz
                    ON bonanza_category_filters (bonanza_id)
            """))

            # 5 — bonanza_extra_commission_log table
            _ec_db.execute(_ec_text("""
                CREATE TABLE IF NOT EXISTS bonanza_extra_commission_log (
                    id           SERIAL PRIMARY KEY,
                    bonanza_id   INTEGER NOT NULL REFERENCES bonanza(id) ON DELETE CASCADE,
                    lead_id      INTEGER NOT NULL,
                    level        INTEGER NOT NULL,
                    partner_id   INTEGER,
                    vci_entry_id INTEGER,
                    created_at   TIMESTAMP NOT NULL DEFAULT NOW(),
                    CONSTRAINT uq_bonanza_ec_log UNIQUE (bonanza_id, lead_id, level)
                )
            """))
            _ec_db.execute(_ec_text("""
                CREATE INDEX IF NOT EXISTS idx_bec_log_bonanza
                    ON bonanza_extra_commission_log (bonanza_id)
            """))
            _ec_db.execute(_ec_text("""
                CREATE INDEX IF NOT EXISTS idx_bec_log_lead
                    ON bonanza_extra_commission_log (lead_id)
            """))

            # 6 — Expand vgk_cash_income_entries kind CHECK to include EXTRA_COMMISSION
            _ec_db.execute(_ec_text("""
                ALTER TABLE vgk_cash_income_entries
                    DROP CONSTRAINT IF EXISTS vgk_cash_income_kind_check
            """))
            _ec_db.execute(_ec_text("""
                ALTER TABLE vgk_cash_income_entries
                    ADD CONSTRAINT vgk_cash_income_kind_check
                    CHECK (kind IN (
                        'COMMISSION','ADVANCE','BRAND_ADVANCE','BRAND_COMMISSION',
                        'SENIOR_COMM','SLAB_BONUS','ADJUSTMENT','DVR_ADVANCE','EXTRA_COMMISSION'
                    ))
            """))

            # 7 — Expand vgk_wallet_transactions txn_type CHECK to include EXTRA_COMMISSION_CREDIT
            _ec_db.execute(_ec_text("""
                ALTER TABLE vgk_wallet_transactions
                    DROP CONSTRAINT IF EXISTS vgk_wallet_transactions_txn_type_check
            """))
            _ec_db.execute(_ec_text("""
                ALTER TABLE vgk_wallet_transactions
                    ADD CONSTRAINT vgk_wallet_transactions_txn_type_check
                    CHECK (txn_type IN (
                        'INCOME_CREDIT','INCOME_DEDUCTION',
                        'SERVICE_DEBIT','VENDOR_DEBIT',
                        'WITHDRAWAL','ADJUSTMENT',
                        'SOLAR_ADVANCE_CREDIT','SLAB_BONUS_CREDIT','SOLAR_ADVANCE_RECOVERY',
                        'SOLAR_ADV_PAYOUT','SLAB_BONUS_PAYOUT',
                        'COMPANY_PAYOUT','COMPANY_PAYOUT_DEDUCT',
                        'BONANZA_CASH_PAYOUT','ADVANCE_CASH_PAID',
                        'EXTRA_COMMISSION_CREDIT'
                    ))
            """))

            _ec_db.execute(
                _ec_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _ec_mk}
            )
            _ec_db.commit()
            print("[DC-EXTRA-COMM-001] ✅ Schema migration applied: extra_commission bonanza tables + constraints", flush=True)
        else:
            print("[DC-EXTRA-COMM-001] ⏭️ Already applied — skipping", flush=True)
    except Exception as _ec_e:
        print(f"[DC-EXTRA-COMM-001] ⚠️ Non-fatal: {_ec_e}", flush=True)
        try:
            _ec_db.rollback()
        except Exception:
            pass
    finally:
        try:
            _ec_db.close()
        except Exception:
            pass
except Exception as _ec_outer:
    print(f"[DC-EXTRA-COMM-001] ⚠️ Outer error: {_ec_outer}", flush=True)

# DC-WA-TRACK-001: Public WhatsApp link tracking redirect (no auth — external leads click this)
@app.get("/api/v1/wa-redirect/{token}")
async def wa_link_redirect(token: str):
    """
    Public redirect endpoint for WhatsApp tracked links.
    Increments click_count on wa_link_tracks row, then 302-redirects to target_url.
    Called by leads/customers clicking links sent via WhatsApp.
    """
    from sqlalchemy import text as _sql_t
    from starlette.responses import RedirectResponse
    _db = SessionLocal()
    try:
        row = _db.execute(_sql_t(
            "SELECT id, target_url FROM wa_link_tracks WHERE token = :t"
        ), {"t": token}).fetchone()
        if not row:
            return RedirectResponse(url="https://mnrteam.com", status_code=302)
        target_url = row[1]
        _db.execute(_sql_t("""
            UPDATE wa_link_tracks
               SET click_count = click_count + 1,
                   last_clicked_at = NOW(),
                   first_clicked_at = COALESCE(first_clicked_at, NOW())
             WHERE id = :rid
        """), {"rid": row[0]})
        _db.commit()
        return RedirectResponse(url=target_url, status_code=302)
    except Exception as _e:
        logging.warning(f"[DC-WA-TRACK-001] Redirect error for token={token}: {_e}")
        return RedirectResponse(url="https://mnrteam.com", status_code=302)
    finally:
        _db.close()


