# Object Storage - Serve media files from App Storage OR Local Storage
# DC Protocol: Full HTTP Range request support for video/audio/PDF seeking
@app.get("/storage/{file_path:path}")
async def serve_storage_file(request: Request, file_path: str):
    """
    Serve files from Object Storage or Local Storage.
    DC Protocol: Implements RFC 7233 Range requests so HTML5 <video> can seek,
    buffer partially, and show duration. Required for MP4/WebM/PDF playback.
    """
    from fastapi.responses import Response
    from app.services.object_storage import storage_service
    from pathlib import Path

    # ── Content-Type detection ────────────────────────────────────────
    content_type = "application/octet-stream"
    lp = file_path.lower()
    if lp.endswith(('.jpg', '.jpeg')):
        content_type = "image/jpeg"
    elif lp.endswith('.png'):
        content_type = "image/png"
    elif lp.endswith('.gif'):
        content_type = "image/gif"
    elif lp.endswith('.webp'):
        content_type = "image/webp"
    elif lp.endswith('.mp4'):
        content_type = "video/mp4"
    elif lp.endswith('.webm'):
        content_type = "video/webm"
    elif lp.endswith('.mov'):
        content_type = "video/quicktime"
    elif lp.endswith('.pdf'):
        content_type = "application/pdf"

    filename = file_path.split('/')[-1]

    # ── Resolve file data (Object Storage → local fallback) ──────────
    file_data: bytes | None = storage_service.download_file(file_path)

    if file_data is None:
        local_storage_root = Path(__file__).parent.parent.parent / "frontend" / "storage"
        local_path = local_storage_root / file_path
        if local_path.exists() and local_path.is_file():
            file_data = local_path.read_bytes()

    if file_data is None:
        raise HTTPException(status_code=404, detail="File not found")

    file_size = len(file_data)

    # DC-CACHE-001: Images are UUID-named (immutable URLs) → long-lived browser cache.
    # Videos get 1-day cache. PDFs/docs stay no-cache (sensitive, may change).
    _is_img   = content_type.startswith('image/')
    _is_video = content_type.startswith('video/')
    _cache = (
        "public, max-age=31536000, immutable" if _is_img
        else "public, max-age=86400"          if _is_video
        else "no-cache, no-store, must-revalidate"
    )
    base_headers = {
        "Accept-Ranges": "bytes",
        "Content-Type": content_type,
        "Cache-Control": _cache,
        "Content-Disposition": f'inline; filename="{filename}"',
    }
    if not _is_img and not _is_video:
        base_headers["Pragma"] = "no-cache"
        base_headers["Expires"] = "0"

    # ── Range request (HTTP 206 Partial Content — RFC 7233) ───────────
    range_header = request.headers.get("Range")
    if range_header:
        try:
            units, range_spec = range_header.split("=", 1)
            if units.strip() != "bytes":
                raise ValueError("unsupported unit")
            start_str, end_str = range_spec.strip().split("-", 1)
            if not start_str:
                # Suffix-range: bytes=-N  →  last N bytes
                suffix_len = int(end_str)
                start = max(0, file_size - suffix_len)
                end = file_size - 1
            else:
                start = int(start_str)
                end = int(end_str) if end_str.strip() else file_size - 1
            start = max(0, start)
            end = min(end, file_size - 1)
            if start > end:
                raise ValueError("invalid range")
            chunk = file_data[start: end + 1]
            return Response(
                content=chunk,
                status_code=206,
                headers={
                    **base_headers,
                    "Content-Length": str(len(chunk)),
                    "Content-Range": f"bytes {start}-{end}/{file_size}",
                },
            )
        except (ValueError, TypeError):
            raise HTTPException(status_code=416, detail="Range Not Satisfiable")

    # ── Full file response (HTTP 200) ─────────────────────────────────
    return Response(
        content=file_data,
        status_code=200,
        headers={
            **base_headers,
            "Content-Length": str(file_size),
        },
    )

# DC-FIRST-PMT-001: Add first_payment_received_date DATE column to crm_leads and
# backfill from the earliest validated crm_lead_transactions.transaction_date per lead.
# This is the ACTUAL date money was first received — used by:
#   - DVR filter in Solar Leads page (was wrongly using first_dvr_confirmed_at)
#   - Bonanza member-tracking progress counter (was wrongly using crm_lead_deals)
# first_dvr_confirmed_at = system timestamp when DVR advance record was created (unreliable)
# first_payment_received_date = MIN(transaction_date) WHERE validation_status='validated'
try:
    from sqlalchemy import text as _fpr_text
    _fpr_db = SessionLocal()
    _fpr_mk = "first_payment_received_date_20260712"
    try:
        _fpr_exists = _fpr_mk in _applied_keys
        if not _fpr_exists:
            _fpr_db.execute(_fpr_text("""
                ALTER TABLE crm_leads
                ADD COLUMN IF NOT EXISTS first_payment_received_date DATE
            """))
            _fpr_db.commit()
            _fpr_result = _fpr_db.execute(_fpr_text("""
                UPDATE crm_leads cl
                SET first_payment_received_date = sub.min_date
                FROM (
                    SELECT d.lead_id, MIN(t.transaction_date::date) AS min_date
                    FROM crm_lead_transactions t
                    JOIN crm_lead_deals d ON d.id = t.deal_id
                    WHERE t.validation_status = 'validated'
                      AND d.lead_id IS NOT NULL
                    GROUP BY d.lead_id
                ) sub
                WHERE cl.id = sub.lead_id
                  AND cl.first_payment_received_date IS NULL
            """))
            _fpr_updated = _fpr_result.rowcount
            _fpr_db.execute(
                _fpr_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _fpr_mk}
            )
            _fpr_db.commit()
            print(f"[DC-FIRST-PMT-001] ✅ Column added + backfilled {_fpr_updated} leads with first_payment_received_date", flush=True)
        else:
            print("[DC-FIRST-PMT-001] ⏭️ Already applied — skipping", flush=True)
    except Exception as _fpr_e:
        print(f"[DC-FIRST-PMT-001] ⚠️ Non-fatal: {_fpr_e}", flush=True)
        try:
            _fpr_db.rollback()
        except Exception:
            pass
    finally:
        try:
            _fpr_db.close()
        except Exception:
            pass
except Exception as _fpr_outer:
    print(f"[DC-FIRST-PMT-001] ⚠️ Outer error: {_fpr_outer}", flush=True)

# DC-FIRST-PMT-BACKFILL-V2-001 (Jul 2026): Second-pass backfill for
# crm_leads.first_payment_received_date.  The first pass (DC-FIRST-PMT-001) only
# backfilled leads that already had a validated transaction — but if transaction_date
# was NULL on those rows, the date was skipped.  This pass fills any remaining NULLs
# by taking the MIN(transaction_date) from crm_lead_transactions where a validated
# txn exists with a non-NULL transaction_date.
try:
    from sqlalchemy import text as _fpr2_text
    _fpr2_db = SessionLocal()
    _fpr2_mk = "dc_first_pmt_backfill_v2_20260712"
    try:
        _fpr2_exists = _fpr2_mk in _applied_keys
        if not _fpr2_exists:
            _fpr2_result = _fpr2_db.execute(_fpr2_text("""
                UPDATE crm_leads cl
                SET first_payment_received_date = sub.earliest_date
                FROM (
                    SELECT lead_id, MIN(transaction_date)::date AS earliest_date
                    FROM crm_lead_transactions
                    WHERE validation_status = 'validated'
                      AND transaction_date IS NOT NULL
                      AND lead_id IS NOT NULL
                    GROUP BY lead_id
                ) sub
                WHERE cl.id = sub.lead_id
                  AND cl.first_payment_received_date IS NULL
            """))
            _fpr2_updated = _fpr2_result.rowcount
            _fpr2_db.execute(
                _fpr2_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _fpr2_mk}
            )
            _fpr2_db.commit()
            print(f"[DC-FIRST-PMT-BACKFILL-V2] ✅ Backfilled first_payment_received_date for {_fpr2_updated} leads", flush=True)
        else:
            print("[DC-FIRST-PMT-BACKFILL-V2] ⏭️ Already applied — skipping", flush=True)
    except Exception as _fpr2_e:
        print(f"[DC-FIRST-PMT-BACKFILL-V2] ⚠️ Non-fatal: {_fpr2_e}", flush=True)
        try:
            _fpr2_db.rollback()
        except Exception:
            pass
    finally:
        try:
            _fpr2_db.close()
        except Exception:
            pass
except Exception as _fpr2_outer:
    print(f"[DC-FIRST-PMT-BACKFILL-V2] ⚠️ Outer error: {_fpr2_outer}", flush=True)

# DC-ASSOC-PARTNER-SRC-BACKFILL-001 (Jul 2026): For VGK-partner-sourced leads where
# source_ref_type IN ('vgk','vgk_partner','partner') and source_ref_id holds the
# official_partners.id as a string, backfill associated_partner_id so the bonanza
# member-tracking query and claim gate correctly credit the ground-source partner
# (e.g. Velaga Ramnath) even before DC-VGK-PARTNER-SYNC-001 ran on the form save.
try:
    from sqlalchemy import text as _aps_text
    _aps_db = SessionLocal()
    _aps_mk = "dc_assoc_partner_src_backfill_20260712"
    try:
        _aps_exists = _aps_mk in _applied_keys
        if not _aps_exists:
            _aps_result = _aps_db.execute(_aps_text("""
                UPDATE crm_leads cl
                SET associated_partner_id = cl.source_ref_id::int
                FROM official_partners op
                WHERE cl.associated_partner_id IS NULL
                  AND cl.source_ref_type IN ('vgk', 'vgk_partner', 'partner')
                  AND cl.source_ref_id IS NOT NULL
                  AND cl.source_ref_id ~ '^[0-9]+$'
                  AND cl.source_ref_id::int = op.id
            """))
            _aps_updated = _aps_result.rowcount
            _aps_db.execute(
                _aps_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _aps_mk}
            )
            _aps_db.commit()
            print(f"[DC-ASSOC-PARTNER-SRC-BACKFILL] ✅ Backfilled associated_partner_id for {_aps_updated} leads from source_ref_id", flush=True)
        else:
            print("[DC-ASSOC-PARTNER-SRC-BACKFILL] ⏭️ Already applied — skipping", flush=True)
    except Exception as _aps_e:
        print(f"[DC-ASSOC-PARTNER-SRC-BACKFILL] ⚠️ Non-fatal: {_aps_e}", flush=True)
        try:
            _aps_db.rollback()
        except Exception:
            pass
    finally:
        try:
            _aps_db.close()
        except Exception:
            pass
except Exception as _aps_outer:
    print(f"[DC-ASSOC-PARTNER-SRC-BACKFILL] ⚠️ Outer error: {_aps_outer}", flush=True)

# DC-AWARD-TRIGGER-001 (Jul 2026): Schema for award/gift trigger bonanzas.
# 1. bonanza_trigger_log — records every pipeline event fire per (bonanza, partner, lead)
#    UNIQUE(bonanza_id, partner_id, lead_id): each lead counted once per partner per bonanza.
# 2. bonanza.award_level_notes JSONB — per-level participation config for award/gift types.
# 3. bonanza_progress.auto_triggered / trigger_event_source — track auto-created claims.
try:
    from sqlalchemy import text as _at_text
    _at_db = SessionLocal()
    _at_mk = "award_trigger_schema_20260713"
    try:
        _at_exists = _at_mk in _applied_keys
        if not _at_exists:
            _at_db.execute(_at_text("""
                CREATE TABLE IF NOT EXISTS bonanza_trigger_log (
                    id                   SERIAL PRIMARY KEY,
                    bonanza_id           INTEGER NOT NULL REFERENCES bonanza(id) ON DELETE CASCADE,
                    partner_id           INTEGER NOT NULL,
                    lead_id              INTEGER NOT NULL,
                    trigger_event        VARCHAR(30) NOT NULL,
                    consumed_by_claim_id INTEGER REFERENCES bonanza_progress(id) ON DELETE SET NULL,
                    created_at           TIMESTAMP NOT NULL DEFAULT NOW(),
                    CONSTRAINT uq_btl_bonanza_partner_lead
                        UNIQUE (bonanza_id, partner_id, lead_id)
                )
            """))
            _at_db.execute(_at_text("CREATE INDEX IF NOT EXISTS idx_btl_partner_bonanza ON bonanza_trigger_log(bonanza_id, partner_id)"))
            _at_db.execute(_at_text("""
                ALTER TABLE bonanza
                    ADD COLUMN IF NOT EXISTS award_level_notes JSONB
            """))
            _at_db.execute(_at_text("""
                ALTER TABLE bonanza_progress
                    ADD COLUMN IF NOT EXISTS auto_triggered       BOOLEAN DEFAULT FALSE,
                    ADD COLUMN IF NOT EXISTS trigger_event_source VARCHAR(30)
            """))
            _at_db.execute(
                _at_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
                {"k": _at_mk}
            )
            _at_db.commit()
            print("[DC-AWARD-TRIGGER-001] ✅ Schema applied: bonanza_trigger_log + award_level_notes + auto_triggered", flush=True)
        else:
            print("[DC-AWARD-TRIGGER-001] ⏭️  Already applied — skipping", flush=True)
    except Exception as _at_e:
        print(f"[DC-AWARD-TRIGGER-001] ⚠️ Non-fatal: {_at_e}", flush=True)
        try:
            _at_db.rollback()
        except Exception:
            pass
    finally:
        try:
            _at_db.close()
        except Exception:
            pass
except Exception as _at_outer:
    print(f"[DC-AWARD-TRIGGER-001] ⚠️ Outer error: {_at_outer}", flush=True)


