# DC-EC-POSITIVE-TARGET-RELAX-001 (Jul 2026): Relax positive_target CHECK constraint so
# extra_commission bonanzas can store target_requirement = 0 (no target — auto-fires per lead).
# For all other reward types the constraint still requires target_requirement > 0.
try:
    from sqlalchemy import text as _ptr_text
    from app.core.database import SessionLocal as _ptr_SL
    _ptr_db = _ptr_SL()
    _ptr_mk = "positive_target_relaxed_ec_20260713"
    _ptr_exists = _ptr_mk in _applied_keys
    if not _ptr_exists:
        _ptr_db.execute(_ptr_text("""
            ALTER TABLE bonanza DROP CONSTRAINT IF EXISTS positive_target
        """))
        _ptr_db.execute(_ptr_text("""
            ALTER TABLE bonanza ADD CONSTRAINT positive_target CHECK (
                reward_type = 'extra_commission' OR target_requirement > 0
            )
        """))
        _ptr_db.execute(
            _ptr_text("INSERT INTO dc_migrations(key) VALUES(:k) ON CONFLICT(key) DO NOTHING"),
            {"k": _ptr_mk}
        )
        _ptr_db.commit()
        print("[DC-EC-POSITIVE-TARGET-RELAX-001] ✅ positive_target constraint relaxed for extra_commission (target=0 now allowed)", flush=True)
    else:
        print("[DC-EC-POSITIVE-TARGET-RELAX-001] ⏭️  Already applied — skipping", flush=True)
except Exception as _ptr_e:
    print(f"[DC-EC-POSITIVE-TARGET-RELAX-001] ⚠️ Non-fatal: {_ptr_e}", flush=True)
    try:
        _ptr_db.rollback()
    except Exception:
        pass
finally:
    try:
        _ptr_db.close()
    except Exception:
        pass


